# 검색용 평탄화 리스트 (한글명 소문자 + 영문명 소문자)
_GP200_SEARCH_LIST: list = [
    (ko, en, ko.lower(), en.lower()) for ko, en in _GP200_COMPANY_DB
]


def gp200_brand_footer(session_state=None) -> str:
    """
    [GP200 §3] 조건부 브랜딩 푸터 HTML 반환.
    사용자 브랜딩 정보가 있을 때만 [담당: {소속} {성명} | 연락처: {연락처}] 바 렌더링.
    정보가 없으면 빈 문자열 반환 → 푸터 영역 미생성.
    """
    if session_state is None:
        return ""
    _co   = (session_state.get("gp200_company") or "").strip()
    _br   = (session_state.get("gp200_branch")  or "").strip()
    _nm   = (session_state.get("gp200_name")    or "").strip()
    _ct   = (session_state.get("gp200_contact") or "").strip()
    if not (_co or _nm or _ct):
        return ""
    _affil = " ".join(filter(None, [_co, _br]))
    _parts = []
    if _affil:
        _parts.append(f"🏢 {_affil}")
    if _nm:
        _parts.append(f"👤 {_nm} 마스터")
    if _ct:
        _parts.append(f"📞 {_ct}")
    _body = " &nbsp;|&nbsp; ".join(_parts)
    return f"""
<div style="background:linear-gradient(90deg,#0a1628,#1a3a5c);border-radius:0 0 10px 10px;
  padding:8px 16px;margin-top:10px;display:flex;align-items:center;gap:8px;
  border-top:2px solid #D4AF37;">
  <span style="font-size:0.88rem;font-weight:700;color:#D4AF37;letter-spacing:0.04em;">
    담당:
  </span>
  <span style="font-size:0.85rem;color:#e0f0ff;font-weight:600;">
    {_body}
  </span>
</div>"""


def gp200_search_companies(query: str, limit: int = 8) -> list:
    """
    [GP200 §2] 입력 쿼리로 GA/보험사 DB 실시간 검색.
    반환: [(한글명, 영문명), ...] 최대 limit건
    """
    q = query.strip().lower()
    if not q:
        return []
    results = []
    for ko, en, ko_l, en_l in _GP200_SEARCH_LIST:
        if q in ko_l or q in en_l:
            results.append((ko, en))
        if len(results) >= limit:
            break
    return results


