# Python 인터프리터 레벨에서 surrogate 문자를 replace로 강제 치환
# Streamlit 렌더링 엔진은 stdout 설정을 우회하므로
# str 서브클래스 + __str__ 후킹 대신 encode 레벨에서 차단
# ==========================================================
os.environ["PYTHONIOENCODING"] = "utf-8:replace"
