DEFAULT_KEY = b'19IPhRNw7fLHub9g5Kp6BaQ6wi53gJ8-OKPF3Bd5Ays='

def get_encryption_key():
    key = os.environ.get("ENCRYPTION_KEY", "")
    if key:
        return key.encode() if isinstance(key, str) else key
    try:
        if "ENCRYPTION_KEY" in st.secrets:
            return st.secrets["ENCRYPTION_KEY"].encode()
    except Exception:
        pass
    return DEFAULT_KEY

def get_cipher():
    """cipher_suite 지연 초기화 - 모듈 수준 st.secrets 접근 방지"""
    if 'cipher_suite' not in st.session_state:
        st.session_state.cipher_suite = _lazy_fernet()(get_encryption_key())
    return st.session_state.cipher_suite

def encrypt_val(data):
    return get_cipher().encrypt(data.encode()).decode()

def decrypt_val(data):
    try:
        return get_cipher().decrypt(data.encode()).decode()
    except:
        return "Decryption Error"

def encrypt_data(data):
    """단방향 해시 암호화 (연락처 등 민감 정보)"""
    return hashlib.sha256(data.encode()).hexdigest()

def decrypt_data(stored_hash, input_data):
    """해시 비교 검증"""
    return stored_hash == hashlib.sha256(input_data.encode()).hexdigest()

# ★★★ [PII 보호 — 절대명령] ★★★
# 주민등록번호·전화번호·이메일 등 고유식별정보(PII)는
# 반드시 이 함수(단방향 SHA-256 해시)로만 저장해야 한다.
# 원문 평문을 DB·로그·세션에 절대 기록하지 말 것.
# 복호화가 필요한 데이터는 encrypt_val/decrypt_val(Fernet 양방향)을 사용하되,
# 고유식별정보는 단방향 해시만 허용한다. (개인정보보호법 제24조·제29조 준수)
def encrypt_contact(contact):
    return hashlib.sha256(contact.encode()).hexdigest()

def sanitize_unicode(text) -> str:
    """surrogate 문자 완전 제거 — ftfy 우선 + 3단계 방어 (근본 해결판)"""
    if not isinstance(text, str):
        try:
            text = str(text)
        except Exception:
            return ""
    # 0단계: ftfy로 잘못된 인코딩 자체를 수정 (가장 포괄적)
    _ftfy_mod = _lazy_ftfy()
    if _ftfy_mod is not None:
        try:
            text = _ftfy_mod.fix_text(text, normalization="NFC")
        except Exception:
            pass
    # 1단계: 유니코드 카테고리 Cs(surrogate) 문자를 문자 단위로 직접 제거
    try:
        text = "".join(ch for ch in text if unicodedata.category(ch) != "Cs")
    except Exception:
        pass
    # 2단계: UTF-8 왕복으로 잔여 surrogate 완전 제거 (ignore = 흔적 없이 삭제)
    try:
        text = text.encode("utf-8", errors="ignore").decode("utf-8", errors="ignore")
    except Exception:
        pass
    # 3단계: 최후 방어 — repr 폴백
    try:
        text.encode("utf-8")  # 검증
    except (UnicodeEncodeError, UnicodeDecodeError):
        text = repr(text).encode("utf-8", errors="replace").decode("utf-8", errors="replace")
    return text

def normalize_corp_name(name: str) -> str:
    """법인명 정규화 — (주)·주식회사·(유)·유한회사 위치 무관하게 핵심 회사명 추출
    반환: 정규화된 핵심명 (비교·중복 감지용)
    예) '(주)삼성전자' → '삼성전자' / '삼성전자(주식회사)' → '삼성전자'
    """
    if not name:
        return name
    n = name.strip()
    # 앞·뒤 접두/접미 제거 패턴 (순서 중요: 긴 패턴 먼저)
    _corp_patterns = [
        r"^\(주식회사\)\s*", r"^\(주\)\s*", r"^\(유한회사\)\s*", r"^\(유\)\s*",
        r"^주식회사\s*",      r"^유한회사\s*",
        r"\s*\(주식회사\)$",  r"\s*\(주\)$", r"\s*\(유한회사\)$", r"\s*\(유\)$",
        r"\s*주식회사$",      r"\s*유한회사$",
    ]
    for pat in _corp_patterns:
        n = re.sub(pat, "", n).strip()
    return n

def detect_corp_name_conflict(new_name: str, registry: dict) -> tuple[str | None, str]:
    """새 이름이 기존 registry의 이름과 법인명 정규화 기준으로 동일한지 검사
    반환: (기존_키, 경고메시지) or (None, "")
    """
    if not new_name:
        return None, ""
    new_core = normalize_corp_name(new_name)
    for existing_key in registry:
        if existing_key in (new_name, "", "익명 고객"):
            continue
        existing_core = normalize_corp_name(existing_key)
        if existing_core and new_core and existing_core == existing_key and new_name != existing_key:
            continue
        if existing_core and new_core and existing_core == new_core and new_name != existing_key:
            return existing_key, (
                f"⚠️ **법인명 중복 주의**: '{new_name}'은 이미 등록된 '{existing_key}'와 "
                f"동일한 회사로 판단됩니다.\n"
                f"   핵심명: **{new_core}**\n"
                f"   표기를 통일하려면 ✏️ 수정 버튼을 이용하세요."
            )
    return None, ""

# ══════════════════════════════════════════════════════════════════════
# ★ CRM 관계형 데이터 엔진 (Graph-based Customer Relationship Manager)
# ══════════════════════════════════════════════════════════════════════
# 노드(Node) 스키마:
# registry[이름] = {
#   "analyses": [],          # 분석 이력
#   "registered": bool,      # 등록 여부
#   "profile": {
#     "company":   str,      # 소속 법인명 (정규화 전 원본)
#     "title":     str,      # 직위 (대표이사·이사·직원·개인 등)
#     "is_ceo":    bool,     # 법인 대표이사 여부
#     "referrer":  str,      # 소개자 이름 (registry 키)
#     "affinity":  str,      # 연고인 이름
#     "family":    list[str],# 가족 구성원 이름 목록 (registry 키)
#     "family_rel":dict,     # {이름: 관계} e.g. {"홍길순": "배우자"}
#     "memo":      str,      # 자유 메모
#   }
# }

def _crm_init(reg: dict, name: str) -> dict:
    """registry에 name이 없으면 기본 노드 생성 후 반환"""
    if name not in reg:
        reg[name] = {"analyses": [], "registered": False, "profile": {}}
    if "profile" not in reg[name]:
        reg[name]["profile"] = {}
    return reg[name]

def crm_get_profile(reg: dict, name: str) -> dict:
    node = _crm_init(reg, name)
    return node.get("profile", {})

# ── 상해 통합 계산 엔진 (LCRM: Life-Cycle Risk Management) ──────────────────
def hoffman_coeff(n_months: float, rate: float = 0.05) -> float:
    """호프만 단리 계수 — 중간이자 공제 현재가치 환산
    H(n) = n / (1 + n * r / 12)  (r: 연 할인율, 기본 5%)
    """
    if n_months <= 0:
        return 0.0
    return n_months / (1 + n_months * rate / 12)

def classify_injury_type(text: str) -> str:
    """자연어 입력에서 사고 성격 자동 분류 → 'traffic' / 'industrial' / 'general'"""
    t = text.lower()
    traffic_kw  = ["자동차", "오토바이", "차량", "교통사고", "운전", "보행 중", "신호", "추돌", "충돌"]
    industrial_kw = ["업무 중", "출퇴근", "작업장", "공장", "현장", "산재", "근무 중", "직장"]
    if any(k in t for k in traffic_kw):
        return "traffic"
    if any(k in t for k in industrial_kw):
        return "industrial"
    return "general"

def calculate_insurance_gap(
    monthly_income: float,
    disability_rate: float,
    work_loss_months: float,
    rehab_months: float,
    existing_insurance: float = 0,
    social_security: float = 0,
    market_cap: float = 1_500_000_000,
    apply_hoffman: bool = True,
) -> dict:
    """소득 보전형 보장 공백(Gap) 역산 엔진 — 파트1·2·3 설계서 구현
    
    S = ( M × H(T+B) ) / (D/100) - G - P
    M: 월 가처분 소득(원)
    T+B: 휴업+재활 기간(개월)
    D: 장해율(%)
    G: 사회보장 보전액(원)
    P: 기 가입금액(원)
    H: 호프만 계수 (apply_hoffman=False 시 단순 합산)
    """
    if disability_rate <= 0:
        return {"required": 0, "current": existing_insurance, "gap": 0,
                "is_over_limit": False, "depletion_months": 0, "hoffman_applied": apply_hoffman}

    total_months = work_loss_months + rehab_months
    h = hoffman_coeff(total_months) if apply_hoffman else total_months
    total_income_loss = monthly_income * h

    raw_face = total_income_loss / (disability_rate / 100)
    capped   = min(raw_face, market_cap)
    net      = max(0.0, capped - social_security - existing_insurance)
    gap      = net

    # 소득 단절 기간 시각화용: gap / 월소득 = 소득 고갈까지 남은 개월
    depletion_months = round(existing_insurance / monthly_income) if monthly_income > 0 else 0

    return {
        "required":        round(capped),
        "current":         round(existing_insurance),
        "gap":             round(gap),
        "raw_uncapped":    round(raw_face),
        "is_over_limit":   raw_face > market_cap,
        "depletion_months": depletion_months,
        "hoffman_applied": apply_hoffman,
        "total_months":    total_months,
        "h_coeff":         round(h, 2),
    }

