def crm_set_profile(reg: dict, name: str, **kwargs):
    """프로필 필드 업데이트. is_ceo=True 시 법인-대표 연동 자동 처리."""
    node = _crm_init(reg, name)
    p = node["profile"]
    for k, v in kwargs.items():
        if k == "family" and isinstance(v, list):
            p["family"] = list(dict.fromkeys(p.get("family", []) + v))
        elif k == "family_rel" and isinstance(v, dict):
            p.setdefault("family_rel", {}).update(v)
        else:
            p[k] = v
    # 법인-대표 연동: company + is_ceo → 법인 노드에 역참조
    if p.get("is_ceo") and p.get("company"):
        corp = normalize_corp_name(p["company"]) or p["company"]
        _crm_init(reg, corp)
        reg[corp]["profile"].setdefault("ceo_list", [])
        if name not in reg[corp]["profile"]["ceo_list"]:
            reg[corp]["profile"]["ceo_list"].append(name)
    # 소개자 역방향 엣지: referrer → referred_list
    if "referrer" in kwargs and kwargs["referrer"]:
        ref = kwargs["referrer"]
        _crm_init(reg, ref)
        reg[ref]["profile"].setdefault("referred_list", [])
        if name not in reg[ref]["profile"]["referred_list"]:
            reg[ref]["profile"]["referred_list"].append(name)
    # 가족 관계 양방향 엣지
    if "family" in kwargs:
        for fam_name in kwargs["family"]:
            _crm_init(reg, fam_name)
            reg[fam_name]["profile"].setdefault("family", [])
            if name not in reg[fam_name]["profile"]["family"]:
                reg[fam_name]["profile"]["family"].append(name)

def crm_search(reg: dict, query: str) -> list[dict]:
    """이름·회사·소개자·직위 통합 검색 → [{name, profile, score}] 반환"""
    q = query.strip().lower()
    if not q:
        return []
    results = []
    q_corp = normalize_corp_name(q)
    for name, node in reg.items():
        if name in ("", "익명 고객"):
            continue
        p = node.get("profile", {})
        score = 0
        if q in name.lower():
            score += 10
        if q_corp and q_corp in normalize_corp_name(name).lower():
            score += 8
        comp = normalize_corp_name(p.get("company", "")).lower()
        if q in comp or (q_corp and q_corp in comp):
            score += 6
        if q in p.get("title", "").lower():
            score += 3
        if q in p.get("referrer", "").lower():
            score += 2
        if any(q in f.lower() for f in p.get("family", [])):
            score += 4
        if score > 0:
            results.append({"name": name, "profile": p, "score": score})
    return sorted(results, key=lambda x: x["score"], reverse=True)

def crm_get_related(reg: dict, name: str) -> dict:
    """name 기준 연관 고객 전체 조회
    반환: {
      "corp_members": [같은 법인 소속],
      "ceo_of":       [대표인 법인명],
      "referred_by":  소개자 이름,
      "referrals":    [피소개자 목록],
      "family":       [{name, rel}],
      "affinity":     연고인 이름,
    }
    """
    p = crm_get_profile(reg, name)
    result = {
        "corp_members": [], "ceo_of": [], "referred_by": "",
        "referrals": [], "family": [], "affinity": "",
    }
    # 같은 법인 소속
    my_corp = normalize_corp_name(p.get("company", ""))
    if my_corp:
        for n2, node2 in reg.items():
            if n2 == name:
                continue
            p2 = node2.get("profile", {})
            if normalize_corp_name(p2.get("company", "")) == my_corp:
                result["corp_members"].append({
                    "name": n2, "title": p2.get("title", ""), "is_ceo": p2.get("is_ceo", False)
                })
    # 대표이사인 법인
    if p.get("is_ceo") and p.get("company"):
        result["ceo_of"].append(normalize_corp_name(p["company"]) or p["company"])
    # 법인 노드의 ceo_list
    corp_node_key = normalize_corp_name(p.get("company", ""))
    if corp_node_key and corp_node_key in reg:
        result["ceo_of"] = reg[corp_node_key]["profile"].get("ceo_list", [])
    # 소개자·피소개자
    result["referred_by"] = p.get("referrer", "")
    result["referrals"] = p.get("referred_list", [])
    # 가족
    fam_rel = p.get("family_rel", {})
    for fn in p.get("family", []):
        result["family"].append({"name": fn, "rel": fam_rel.get(fn, "가족")})
    # 연고인
    result["affinity"] = p.get("affinity", "")
    return result

def crm_context_for_prompt(reg: dict, name: str) -> str:
    """AI 프롬프트에 주입할 고객 관계 컨텍스트 문자열 생성"""
    if not name or name == "익명 고객":
        return ""
    p = crm_get_profile(reg, name)
    rel = crm_get_related(reg, name)
    lines = []
    if p.get("company"):
        lines.append(f"소속법인: {p['company']} (핵심명: {normalize_corp_name(p['company'])})")
    if p.get("title"):
        lines.append(f"직위: {p['title']}")
    if p.get("is_ceo"):
        lines.append("※ 법인 대표이사 — 개인보험과 법인플랜(경영인정기·CEO플랜) 동시 검토 필요")
    if rel["corp_members"]:
        mlist = ", ".join(f"{m['name']}({m['title'] or '소속'})" for m in rel["corp_members"][:5])
        lines.append(f"동일법인 구성원: {mlist}")
    if rel["referred_by"]:
        lines.append(f"소개자: {rel['referred_by']}")
    if rel["referrals"]:
        lines.append(f"피소개 고객: {', '.join(rel['referrals'][:5])}")
    if rel["family"]:
        fstr = ", ".join(f"{f['name']}({f['rel']})" for f in rel["family"][:5])
        lines.append(f"가족 구성원: {fstr}")
    if rel["affinity"]:
        lines.append(f"연고인: {rel['affinity']}")
    if p.get("phone"):
        _ct = p["phone"]
        if p.get("carrier"):
            _ct += f" ({p['carrier']})"
        lines.append(f"연락처: {_ct}")
    if not lines:
        return ""
    return "\n[고객 관계 정보]\n" + "\n".join(f"- {l}" for l in lines) + "\n"

# ══════════════════════════════════════════════════════════════════════
# ★ CRM Supabase 영구 저장/로드 엔진
# 테이블: gk_crm_clients
#   id           BIGSERIAL PRIMARY KEY
#   agent_uid    TEXT NOT NULL          -- 설계사 user_id
#   client_name  TEXT NOT NULL          -- 고객 이름 (registry 키)
#   profile      JSONB DEFAULT '{}'     -- 프로필 전체 (entity_type, company, title ...)
#   analyses     JSONB DEFAULT '[]'     -- 분석 이력
#   registered   BOOLEAN DEFAULT false  -- 등록고객 여부
#   updated_at   TIMESTAMPTZ DEFAULT now()
#   UNIQUE(agent_uid, client_name)
# ══════════════════════════════════════════════════════════════════════
_CRM_TABLE = "gk_crm_clients"

def crm_save_to_db(reg: dict, agent_uid: str) -> tuple[int, str]:
    """레지스트리 전체를 Supabase에 upsert. 반환: (저장건수, 오류메시지)"""
    sb = _get_sb_client()
    if not sb:
        return 0, "Supabase 미연결"
    if not agent_uid:
        return 0, "로그인 필요"
    rows = []
    for name, node in reg.items():
        if not name or name == "익명 고객":
            continue
        rows.append({
            "agent_uid":   agent_uid,
            "client_name": name,
            "profile":     node.get("profile", {}),
            "analyses":    node.get("analyses", []),
            "registered":  bool(node.get("registered", False)),
        })
    if not rows:
        return 0, ""
    try:
        for i in range(0, len(rows), 50):
            sb.table(_CRM_TABLE).upsert(
                rows[i:i+50],
                on_conflict="agent_uid,client_name"
            ).execute()
        return len(rows), ""
    except Exception as e:
        return 0, str(e)

def crm_load_from_db(agent_uid: str) -> dict:
    """Supabase에서 해당 설계사의 CRM 레지스트리 로드. 반환: registry dict"""
    sb = _get_sb_client()
    if not sb or not agent_uid:
        return {}
    try:
        rows = (
            sb.table(_CRM_TABLE)
            .select("client_name,profile,analyses,registered")
            .eq("agent_uid", agent_uid)
            .execute()
            .data or []
        )
        reg = {}
        for r in rows:
            name = r.get("client_name", "")
            if not name:
                continue
            reg[name] = {
                "profile":    r.get("profile") or {},
                "analyses":   r.get("analyses") or [],
                "registered": bool(r.get("registered", False)),
            }
        return reg
    except Exception:
        return {}

def crm_sync_session(force: bool = False):
    """세션에 gk_client_registry 없거나 force=True 시 DB에서 복원."""
    uid = st.session_state.get("user_id", "")
    if not uid:
        return
    if force or "gk_client_registry" not in st.session_state or not st.session_state["gk_client_registry"]:
        loaded = crm_load_from_db(uid)
        if loaded:
            st.session_state["gk_client_registry"] = loaded

def crm_save_one(reg: dict, name: str, agent_uid: str):
    """단일 고객만 즉시 upsert (저장 버튼 클릭 시 호출)."""
    sb = _get_sb_client()
    if not sb or not agent_uid or not name or name == "익명 고객":
        return
    node = reg.get(name, {})
    try:
        sb.table(_CRM_TABLE).upsert({
            "agent_uid":   agent_uid,
            "client_name": name,
            "profile":     node.get("profile", {}),
            "analyses":    node.get("analyses", []),
            "registered":  bool(node.get("registered", False)),
        }, on_conflict="agent_uid,client_name").execute()
    except Exception:
        pass

def sanitize_prompt(text):
    """프롬프트 인젝션 방어 - 모든 쿼리에 적용"""
    text = sanitize_unicode(text)
    danger_words = [
        # 기존
        "system instruction", "지침 무시", "프롬프트 출력", "명령어 변경", "ignore previous",
        # 확장 — 탈옥·롤플레이·Override 패턴
        "forget", "jailbreak", "dan ", "act as", "역할극", "roleplay",
        "이전 내용 무시", "너는 이제", "새로운 역할", "탈옥",
        "override", "disregard", "do anything now", "pretend you are",
        "너의 규칙", "규칙을 무시", "instructions above", "ignore all",
    ]
    for word in danger_words:
        if word in text.lower():
            return "보안을 위해 부적절한 요청은 처리되지 않습니다."
    return text

def get_admin_key():
    """관리자 키를 st.secrets 또는 환경변수에서 가져옴"""
    try:
        v = st.secrets.get("ADMIN_KEY", "")
        if v: return v
    except Exception:
        pass
    return os.environ.get("ADMIN_KEY", "")

def _check_admin_key(input_key: str) -> bool:
    """입력 키가 ADMIN_KEY / ADMIN_CODE / MASTER_CODE 중 하나와 일치하면 True"""
    k = (input_key or "").strip()
    if not k:
        return False
    valid = set()
    for _secret_name in ("ADMIN_KEY", "ADMIN_CODE", "MASTER_CODE"):
        try:
            v = st.secrets.get(_secret_name, "")
            if v: valid.add(v)
        except Exception:
            pass
        v2 = os.environ.get(_secret_name, "")
        if v2: valid.add(v2)
    return k in valid

def get_admin_code():
    """관리자 코드를 st.secrets 또는 환경변수에서 가져옴"""
    try:
        v = st.secrets.get("ADMIN_CODE", "")
        if v: return v
    except Exception:
        pass
    return os.environ.get("ADMIN_CODE", "")

# --------------------------------------------------------------------------
# [SECTION 1.8] Brute-force 로그인 방어 — _LoginGuard
# --------------------------------------------------------------------------
@st.cache_resource
def _get_login_fail_store():
    """
    서버 전역 로그인 실패 기록 저장소.
    구조: {user_name: {"count": N, "locked_until": float_timestamp}}
    """
    return {}

class _LoginGuard:
    """
    로그인 Brute-force 방어.
    - 5회 연속 실패 → LOCK_MINUTES(10분) 잠금
    - 잠금 중 시도 시 남은 시간 반환
    - 로그인 성공 시 카운터 초기화
    """
    MAX_FAIL    = 5
    LOCK_MINUTES = 10

    @staticmethod
    def is_locked(user_name: str) -> tuple:
        """
        반환: (잠금여부: bool, 남은초: int)
        """
        store = _get_login_fail_store()
        rec   = store.get(user_name)
        if not rec:
            return False, 0
        locked_until = rec.get("locked_until", 0)
        remaining    = int(locked_until - time.time())
        if remaining > 0:
            return True, remaining
        return False, 0

    @staticmethod
    def record_fail(user_name: str):
        """실패 1회 기록. MAX_FAIL 초과 시 잠금 설정."""
        store = _get_login_fail_store()
        rec   = store.setdefault(user_name, {"count": 0, "locked_until": 0})
        rec["count"] += 1
        if rec["count"] >= _LoginGuard.MAX_FAIL:
            rec["locked_until"] = time.time() + _LoginGuard.LOCK_MINUTES * 60
            rec["count"]        = 0  # 잠금 후 카운터 리셋

    @staticmethod
    def record_success(user_name: str):
        """로그인 성공 시 실패 기록 초기화."""
        _get_login_fail_store().pop(user_name, None)

    @staticmethod
    def remaining_attempts(user_name: str) -> int:
        """남은 허용 횟수 (잠금 아닌 경우에만 의미 있음)"""
        store = _get_login_fail_store()
        rec   = store.get(user_name, {"count": 0})
        return max(0, _LoginGuard.MAX_FAIL - rec.get("count", 0))

# --------------------------------------------------------------------------
# [SECTION 1.5] 비상장주식 평가 엔진 (상증법 + 법인세법)
# --------------------------------------------------------------------------
class AdvancedStockEvaluator:
    """
    상증법 및 법인세법 통합 비상장주식 평가 엔진
    """
    def __init__(self, net_asset, net_incomes, total_shares,
                 market_price=None, is_controlling=False, is_real_estate_rich=False):
        self.net_asset           = net_asset
        self.net_incomes         = net_incomes
        self.total_shares        = total_shares
        self.market_price        = market_price
        self.is_controlling      = is_controlling
        self.is_real_estate_rich = is_real_estate_rich
        self.cap_rate            = 0.1
        self.annuity_factor      = 3.7908

    def evaluate_corporate_tax(self):
        if self.market_price:
            base_val    = self.market_price
            method_name = "매매사례가액 (Primary Market Price)"
        else:
            result      = self.evaluate_inheritance_tax()
            base_val    = result['최종 평가액 (할증 전)']
            method_name = "보충적 평가방법 (Supplementary Method)"
        final_val = base_val * 1.2 if self.is_controlling else base_val
        return {
            "평가 방식":        method_name,
            "경영권 할증 적용": "Yes (20%)" if self.is_controlling else "No",
            "법인세법상 시가":  round(final_val, 2),
        }

    def evaluate_inheritance_tax(self):
        pure_asset_per_share = self.net_asset / max(self.total_shares, 1)
        incomes = (self.net_incomes + [0, 0, 0])[:3]
        weighted_eps = (
            incomes[0] / max(self.total_shares, 1) * 3 +
            incomes[1] / max(self.total_shares, 1) * 2 +
            incomes[2] / max(self.total_shares, 1) * 1
        ) / 6
        excess_earnings   = (weighted_eps * 0.5) - (pure_asset_per_share * 0.1)
        goodwill          = max(0, excess_earnings * self.annuity_factor)
        final_asset_value = pure_asset_per_share + goodwill
        earnings_value    = weighted_eps / self.cap_rate
        weight_eps, weight_asset = (2, 3) if self.is_real_estate_rich else (3, 2)
        weighted_avg   = (earnings_value * weight_eps + final_asset_value * weight_asset) / 5
        floor_value    = final_asset_value * 0.8
        base_valuation = max(weighted_avg, floor_value)
        final_valuation = base_valuation * 1.2 if self.is_controlling else base_valuation
        return {
            "주당 순자산가치":        round(final_asset_value, 2),
            "주당 순손익가치":        round(earnings_value, 2),
            "최종 평가액 (할증 전)": round(base_valuation, 2),
            "경영권 할증 적용":       "Yes (20%)" if self.is_controlling else "No",
            "상증법상 최종가액":      round(final_valuation, 2),
        }

