# [SECTION 2] 데이터베이스 및 회원 관리
# --------------------------------------------------------------------------
def _get_db_conn(db_path: str):
    """WAL 모드 + busy_timeout 적용 SQLite 커넥션 반환 (동시 접속 안정화)"""
    conn = sqlite3.connect(db_path, check_same_thread=False, timeout=10)
    conn.execute("PRAGMA journal_mode=WAL")   # 동시 읽기/쓰기 충돌 방지
    conn.execute("PRAGMA busy_timeout=5000")  # 5초 대기 후 재시도
    conn.execute("PRAGMA synchronous=NORMAL") # 성능/안정성 균형
    conn.execute("PRAGMA cache_size=-8000")   # 8MB 캐시
    conn.execute("PRAGMA temp_store=MEMORY")  # 임시 데이터 메모리 저장
    return conn

def setup_database():
    try:
        _db_path = os.path.join(_DATA_DIR, 'insurance_data.db')
        conn = _get_db_conn(_db_path)
        cursor = conn.cursor()
        cursor.execute('''CREATE TABLE IF NOT EXISTS user_documents (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            user_id TEXT NOT NULL,
            document_url TEXT,
            status TEXT DEFAULT 'ACTIVE',
            expiry_date DATE,
            created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP)''')
        conn.commit()
        conn.close()
    except (sqlite3.OperationalError, OSError):
        pass  # Cloud 환경 DB 생성 실패 시 앱 크래시 방지

@st.cache_resource
def _get_member_cache():
    """회원 목록 TTL 캐시 저장소 {data, ts}"""
    return {"data": None, "ts": 0.0}

def load_members(force: bool = False):
    """회원 목록 로드 — [PERF §3] 세션 캐시 → 프로세스 캐시(300초 TTL) → Supabase → /tmp JSON 폴백
    force=True: 캐시 무시하고 즉시 재로드 (가입/저장 직후 호출용)
    """
    # ── [PERF §3] 세션 내 즉시 반환 (네트워크 0회) ───────────────────────
    if not force and "_members_cache" in st.session_state:
        return st.session_state["_members_cache"]
    _cache = _get_member_cache()
    _now = time.time()
    # ── 프로세스 캐시 유효 시 즉시 반환 (300초 TTL) ────────────────────────
    if not force and _cache["data"] is not None and (_now - _cache["ts"]) < 300:
        return _cache["data"]
    # ── Supabase 우선 ────────────────────────────────────────────────────
    if _SB_PKG_OK:
        try:
            sb = _get_sb_client()
            if sb:
                rows = sb.table("gk_members").select("*").execute().data or []
                result = {r["name"]: {
                    "user_id":          r.get("user_id", ""),
                    "contact":          r.get("contact", ""),
                    "join_date":        r.get("join_date", ""),
                    "subscription_end": r.get("subscription_end", ""),
                    "is_active":        bool(r.get("is_active", True)),
                    "pin_hash":         r.get("pin_hash", "") or "",
                    "status":           r.get("status", "active") or "active",
                    "dormant_since":    r.get("dormant_since", "") or "",
                } for r in rows}
                _cache["data"] = result
                _cache["ts"]   = _now
                st.session_state["_members_cache"] = result
                return result
        except Exception:
            pass
    # ── /tmp JSON 폴백 ───────────────────────────────────────────────────
    if not os.path.exists(MEMBER_DB):
        return {}
    try:
        with open(MEMBER_DB, "r", encoding="utf-8") as f:
            result = json.load(f)
            _cache["data"] = result
            _cache["ts"]   = _now
            return result
    except (json.JSONDecodeError, IOError):
        return {}

def save_members(members):
    """회원 목록 저장 — Supabase 우선(필수), /tmp JSON 보조 이중 저장
    ⚠️ Cloud 환경(/tmp)는 재시작 시 휘발 — Supabase가 진짜 영속 저장소
    """
    _sb_ok = False
    _sb_err = ""
    # ── Supabase 우선 (Cloud 환경에서는 여기만이 영속 저장) ────────────
    if _SB_PKG_OK:
        try:
            sb = _get_sb_client()
            if sb:
                for name, m in members.items():
                    _row = {
                        "name":             name,
                        "user_id":          m.get("user_id", ""),
                        "contact":          m.get("contact", ""),
                        "join_date":        m.get("join_date", ""),
                        "subscription_end": m.get("subscription_end", ""),
                        "is_active":        bool(m.get("is_active", True)),
                        "status":           m.get("status", "active") or "active",
                        "dormant_since":    m.get("dormant_since", "") or "",
                    }
                    if m.get("pin_hash", ""):
                        _row["pin_hash"] = m["pin_hash"]
                    sb.table("gk_members").upsert(_row, on_conflict="name").execute()
                _get_member_cache().update({"data": None, "ts": 0.0})
                st.session_state.pop("_members_cache", None)
                _sb_ok = True
        except Exception as _e:
            _sb_err = str(_e)
    # Supabase 저장 성공 시 이미 return
    if _sb_ok:
        return
    # ── Cloud 환경에서 Supabase 실패 — 경고 기록 (session_state 저장) ─────
    if _IS_CLOUD:
        _warn_key = "_member_save_warn"
        st.session_state[_warn_key] = (
            f"⚠️ 회원 저장 Supabase 실패 — 재시작 시 회원정보가 소실될 수 있습니다. | {_sb_err}"
        )
    # ── /tmp JSON 보조 저장 (Cloud에서는 Supabase 복구 시까지 임시 보유용) ──
    try:
        import tempfile, shutil
        tmp_fd, tmp_path = tempfile.mkstemp(dir=os.path.dirname(MEMBER_DB) or '.', suffix='.tmp')
        with os.fdopen(tmp_fd, 'w', encoding='utf-8') as f:
            json.dump(members, f, ensure_ascii=False)
        shutil.move(tmp_path, MEMBER_DB)
        _get_member_cache().update({"data": None, "ts": 0.0})
        st.session_state.pop("_members_cache", None)
    except (IOError, OSError):
        pass

