def add_member(name, contact):
    """신규 회원 등록 - 연락처는 해시 암호화 저장
    동명이인 처리: 이름이 같아도 연락처가 다르면 별도 가입 허용.
    이름+연락처 모두 동일하면 SAME_PERSON (재가입 차단).
    이름만 같고 연락처 다름 → 동명이인 또는 비번분실 재가입:
      - 기존 계정이 active이면 dormant_pw_lost 처리 후 새 이름(번호 부여)으로 가입.
      - 기존 계정이 이미 dormant이면 추가 dormant 없이 새 이름만 부여.
    """
    members = load_members()
    _today = dt.now().strftime("%Y-%m-%d")
    if name in members:
        # 이름+연락처 동시 비교 — 완전 동일인 여부 판단
        if decrypt_data(members[name]["contact"], contact):
            # 이름도 같고 연락처도 같음 → 완전 동일인 재가입 → 차단
            raise ValueError(f"SAME_PERSON:{name}")
        else:
            # 이름은 같지만 연락처 다름 → 동명이인 또는 비번분실 재가입
            # 기존 active 계정이 있으면 dormant_pw_lost 상태로 전환
            if members[name].get("status", "active") == "active":
                members[name]["status"]        = "dormant_pw_lost"
                members[name]["dormant_since"] = _today
                members[name]["is_active"]     = False
            # 새 계정에 쓸 이름 결정: 이름(2), 이름(3) ... 순으로 부여
            _suffix = 2
            while f"{name}({_suffix})" in members:
                _existing = members[f"{name}({_suffix})"]
                # 이미 dormant_pw_lost 슬롯이면 건너뜀
                if _existing.get("status", "active") != "active":
                    _suffix += 1
                    continue
                # active 동명이인 존재 → 연락처 비교
                if decrypt_data(_existing["contact"], contact):
                    raise ValueError(f"SAME_PERSON:{name}({_suffix})")
                _suffix += 1
            name = f"{name}({_suffix})"
    user_id = "GK_" + name + "_" + str(int(time.time()))
    join_date = _today
    end_date = (dt.now() + timedelta(days=365)).strftime("%Y-%m-%d")
    members[name] = {
        "user_id": user_id,
        "contact": encrypt_contact(contact),  # 평문 저장 금지 → 해시 저장
        "join_date": join_date,
        "subscription_end": end_date,
        "is_active": True,
        "status":   "active",
        "dormant_since": "",
    }
    save_members(members)
    # [GP-IMMORTAL §4] 재가입 시 연락처 기반 자동 복구 인덱스 스캔
    try:
        _prev_packages = _gp_auto_recover_by_contact(contact)
        if _prev_packages:
            import streamlit as _st_recv
            _st_recv.session_state["_gp_recovery_packages"] = _prev_packages
            _st_recv.session_state["_gp_recovery_contact"]  = contact
    except Exception:
        pass
    return members[name]

# --------------------------------------------------------------------------
# [SECTION 2-B] 동시접속 관리 + 회원수 임계치 알림
# [가이딩 프로토콜 제49조] 멀티 디바이스 심리스 접속 — Device-specific session
# --------------------------------------------------------------------------
MAX_CONCURRENT = 105  # [GP-49] 기기당 1슬롯 × 최대 3기기 × 35명 기준 상향
SESSION_TTL = 7200    # [가이딩 프로토콜 제37조 §1] 상담 세션 유지 시간 (초, 2시간)
# [GP-49] 로그인 사용자 1계정당 최대 허용 동시 기기 수
MAX_DEVICES_PER_USER = 3

@st.cache_resource
def _get_session_store():
    """서버 전역 접속 세션 추적 저장소
    [GP-49] 구조: {session_id: {"ts": timestamp, "user_id": str, "device_id": str}}
    session_id = "<user_id>:<device_uuid>" (로그인) 또는 "anon_<uuid>" (익명)
    """
    return {}

@st.cache_resource
def _get_alert_store():
    """관리자 임계치 알림 발송 기록 {threshold: True}"""
    return {}

def _session_checkin(session_id: str, user_id: str = "") -> bool:
    """
    [GP-49] 세션 체크인 — Device-specific 멀티 세션 허용.
    반환값:
      True  = 접속 허용
      False = 접속 거부 (익명 트래픽 MAX_CONCURRENT 초과 시만)
    로그인 사용자: MAX_CONCURRENT 제한 완전 면제,
                  동일 user_id 최대 MAX_DEVICES_PER_USER(3)기기까지 허용.
    익명 사용자:   서버 전체 슬롯 여유 시만 허용.
    """
    store = _get_session_store()
    now = time.time()
    # SESSION_TTL 초과 세션 만료 처리
    expired = [k for k, v in list(store.items()) if now - v["ts"] > SESSION_TTL]
    for k in expired:
        store.pop(k, None)
    # 이미 등록된 세션 — 갱신 후 허용
    if session_id in store:
        store[session_id]["ts"] = now
        return True
    # [GP-49] 로그인 사용자 — MAX_CONCURRENT 면제, 기기 수만 확인
    if user_id:
        _user_devices = [k for k, v in store.items() if v.get("user_id") == user_id]
        if len(_user_devices) >= MAX_DEVICES_PER_USER:
            # 가장 오래된 기기 슬롯 해제 후 신규 허용 (LRU 방식)
            _oldest = min(_user_devices, key=lambda k: store[k]["ts"])
            store.pop(_oldest, None)
        store[session_id] = {"ts": now, "user_id": user_id, "device_id": session_id}
        return True
    # 익명 사용자 — 서버 슬롯 여유 시만 허용
    _anon_count = sum(1 for v in store.values() if not v.get("user_id"))
    if _anon_count < MAX_CONCURRENT:
        store[session_id] = {"ts": now, "user_id": "", "device_id": session_id}
        return True
    return False  # 익명 트래픽 초과 → 대기 안내

def _session_checkout(session_id: str):
    """로그아웃 시 해당 기기 세션만 해제 (다른 기기 세션 유지)"""
    _get_session_store().pop(session_id, None)

def _get_concurrent_count() -> int:
    store = _get_session_store()
    now = time.time()
    return sum(1 for v in store.values() if now - v["ts"] <= SESSION_TTL)

def _get_session_remaining(session_id: str) -> int:
    """현재 세션의 남은 시간(초) 반환. 세션 없으면 0"""
    store = _get_session_store()
    entry = store.get(session_id)
    if entry is None:
        return 0
    remaining = SESSION_TTL - int(time.time() - entry["ts"])
    return max(0, remaining)

def _check_member_thresholds():
    """
    회원 수가 50/80/200명 임계치 도달 시 관리자 탭 알림 플래그 설정.
    실제 SMS 대신 앱 내 관리자 배너로 표시.
    """
    alert = _get_alert_store()
    members = load_members()
    cnt = len(members)
    for threshold in [50, 80, 200, 500]:
        key = f"th_{threshold}"
        if cnt >= threshold and key not in alert:
            alert[key] = {"count": cnt, "time": dt.now().strftime("%Y-%m-%d %H:%M")}

# --------------------------------------------------------------------------
# 에러 로그 기록 (파일 기반 — /tmp/error_log.json 영구 저장, 최근 200건)
# --------------------------------------------------------------------------
ERROR_LOG_PATH = "/tmp/error_log.json"

def log_error(source: str, message: str):
    """에러 발생 시각·출처·내용을 파일에 영구 저장 (최근 200건 유지)"""
    ts = dt.now().strftime("%Y-%m-%d %H:%M:%S")
    # surrogate 문자 포함 시 json.dump 자체가 실패하므로 저장 전 반드시 정제
    safe_msg = message.encode("utf-8", errors="replace").decode("utf-8", errors="replace")[:300]
    try:
        logs = []
        if os.path.exists(ERROR_LOG_PATH):
            with open(ERROR_LOG_PATH, "r", encoding="utf-8") as f:
                logs = json.load(f)
        logs.append({"time": ts, "source": source, "message": safe_msg})
        logs = logs[-200:]  # 최근 200건만 유지
        with open(ERROR_LOG_PATH, "w", encoding="utf-8") as f:
            json.dump(logs, f, ensure_ascii=False)
        load_error_log.clear()  # 캐시 무효화
    except (IOError, OSError, json.JSONDecodeError):
        pass  # 로그 저장 실패는 무시

@st.cache_data(ttl=10)
def load_error_log() -> list:
    """저장된 에러 로그 파일 읽기"""
    try:
        if os.path.exists(ERROR_LOG_PATH):
            with open(ERROR_LOG_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
    except (IOError, json.JSONDecodeError):
        pass
    return []

