# [Supabase Storage 연동] 보험 문서 자동 분류 시스템
# secrets.toml [supabase] 섹션에 url, service_role_key 등록 필요
#
# 버킷/폴더 구조 (자동 생성):
#   버킷: goldkey
#   ├── 약관/{보험사}/{연도}/{파일명}.pdf
#   ├── 리플렛/{보험사}/{파일명}.pdf
#   └── 신규상품/{파일명}.pdf  ← 미분류 폴백
# --------------------------------------------------------------------------
SB_BUCKET = "goldkey"
GCS_BUCKET = "insu-archive-2026"  # GCS 예비 버킷명 (용량 초과 시 자동 폴백)

# ══════════════════════════════════════════════════════════════════════════════
# [하이브리드 아키텍처 연동] 카탈로그 API 클라이언트
# catalog_app/backend (FastAPI) 와 app.py 를 연결하는 경량 클라이언트
# 환경변수 HYBRID_BACKEND_URL 이 없으면 자동으로 비활성화 (기존 앱 영향 없음)
# ══════════════════════════════════════════════════════════════════════════════
_HYBRID_BACKEND_URL = os.environ.get("HYBRID_BACKEND_URL", "").rstrip("/")

def _hybrid_enabled() -> bool:
    return bool(_HYBRID_BACKEND_URL)

def _hybrid_headers(jwt_token: str = "") -> dict:
    h = {"Content-Type": "application/json"}
    if jwt_token:
        h["Authorization"] = f"Bearer {jwt_token}"
    return h

def hybrid_login(email: str, password: str) -> dict:
    """카탈로그 API 로그인 → JWT 토큰 반환. 실패 시 빈 dict."""
    if not _hybrid_enabled():
        return {}
    try:
        import urllib.request, json as _json
        data = _json.dumps({"email": email, "password": password}).encode()
        req  = urllib.request.Request(
            f"{_HYBRID_BACKEND_URL}/auth/login", data=data,
            headers={"Content-Type": "application/json"}, method="POST")
        with urllib.request.urlopen(req, timeout=8) as resp:
            return _json.loads(resp.read())
    except Exception:
        return {}

def hybrid_get_public_companies() -> list:
    """공용 보험사 카탈로그 목록 조회 (Public Zone)."""
    if not _hybrid_enabled():
        return []
    try:
        import urllib.request, json as _json
        with urllib.request.urlopen(
                f"{_HYBRID_BACKEND_URL}/public/companies", timeout=8) as resp:
            return _json.loads(resp.read())
    except Exception:
        return []

def hybrid_get_private_files(uid: str, jwt_token: str) -> list:
    """해당 UID 의 개인 카탈로그 목록 조회 (Private Zone)."""
    if not _hybrid_enabled() or not uid or not jwt_token:
        return []
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            f"{_HYBRID_BACKEND_URL}/private/{uid}/list",
            headers=_hybrid_headers(jwt_token))
        with urllib.request.urlopen(req, timeout=8) as resp:
            return _json.loads(resp.read())
    except Exception:
        return []

def hybrid_rag_query(uid: str, jwt_token: str, query: str) -> str:
    """
    RAG 통합 상담 — 공용 지식 + 개인 문서 병합 후 Gemini 답변 반환.
    답변 후 서버측 컨텍스트 즉시 휘발.
    """
    if not _hybrid_enabled() or not uid or not jwt_token:
        return ""
    try:
        import urllib.request, json as _json
        data = _json.dumps({"query": query}).encode()
        req  = urllib.request.Request(
            f"{_HYBRID_BACKEND_URL}/private/{uid}/rag",
            data=data, headers=_hybrid_headers(jwt_token), method="POST")
        with urllib.request.urlopen(req, timeout=30) as resp:
            result = _json.loads(resp.read())
            return result.get("answer", "")
    except Exception:
        return ""

def hybrid_purge_user(uid: str, jwt_token: str) -> bool:
    """
    회원 탈퇴 시 Private Zone 완전 삭제.
    Storage 파일 + DB 메타데이터 + 계정 모두 제거.
    """
    if not _hybrid_enabled() or not uid or not jwt_token:
        return False
    try:
        import urllib.request, json as _json
        req = urllib.request.Request(
            f"{_HYBRID_BACKEND_URL}/private/{uid}/purge",
            headers=_hybrid_headers(jwt_token), method="DELETE")
        with urllib.request.urlopen(req, timeout=15) as resp:
            return _json.loads(resp.read()).get("status") == "purged"
    except Exception:
        return False
# ══════════════════════════════════════════════════════════════════════════════

def _lazy_sb_create_client():
    """supabase: DB 접근 시점에만 로드 (부팅 ~0.6s 절감)"""
    try:
        from supabase import create_client as _c
        return _c
    except Exception:
        return None

_SB_PKG_OK = True  # 실제 가용 여부는 _lazy_sb_create_client() 호출 시 결정

@st.cache_resource
def _get_gcs_client_cached():
    """GCS 클라이언트 싱글톤 — @st.cache_resource로 프로세스당 1회만 인증 수행.
    [PERF §1] 매 rerun마다 OAuth 인증을 반복하던 병목 제거.
    우선순위 1: secrets.toml [gcs] 섹션
    우선순위 2: HF Secrets 환경변수 GCS_*
    """
    try:
        from google.cloud import storage
        from google.oauth2 import service_account
        gcs_cfg = {}
        try:
            gcs_cfg = dict(st.secrets.get("gcs", {}))
        except Exception:
            pass
        if not gcs_cfg or not gcs_cfg.get("private_key"):
            pk = os.environ.get("GCS_PRIVATE_KEY", "")
            if pk:
                gcs_cfg = {
                    "type":           os.environ.get("GCS_TYPE", "service_account"),
                    "project_id":     os.environ.get("GCS_PROJECT_ID", ""),
                    "private_key_id": os.environ.get("GCS_PRIVATE_KEY_ID", ""),
                    "private_key":    pk.replace("\\n", "\n"),
                    "client_email":   os.environ.get("GCS_CLIENT_EMAIL", ""),
                    "client_id":      os.environ.get("GCS_CLIENT_ID", ""),
                    "auth_uri":       "https://accounts.google.com/o/oauth2/auth",
                    "token_uri":      "https://oauth2.googleapis.com/token",
                }
        if not gcs_cfg or not gcs_cfg.get("private_key"):
            return None
        creds = service_account.Credentials.from_service_account_info(
            gcs_cfg, scopes=["https://www.googleapis.com/auth/cloud-platform"]
        )
        return storage.Client(credentials=creds, project=gcs_cfg.get("project_id"))
    except Exception:
        return None

def _get_gcs_client():
    """GCS 클라이언트 반환 — 캐싱된 싱글톤 위임 래퍼."""
    return _get_gcs_client_cached()

# ── GCS 분석 캐시 헬퍼 (Cache-First 비용 절감) ─────────────────────────────
_GCS_CACHE_BUCKET = None  # 앱 시작 시 환경변수/secrets에서 설정

def _get_gcs_cache_bucket():
    """GCS 캐시 버킷명 반환 — 환경변수 > secrets > None"""
    global _GCS_CACHE_BUCKET
    if _GCS_CACHE_BUCKET:
        return _GCS_CACHE_BUCKET
    try:
        _GCS_CACHE_BUCKET = os.environ.get("GCS_CACHE_BUCKET") or st.secrets.get("GCS_CACHE_BUCKET", "")
    except Exception:
        _GCS_CACHE_BUCKET = os.environ.get("GCS_CACHE_BUCKET", "")
    return _GCS_CACHE_BUCKET or None

def _gcs_cache_key(user_name: str, query: str, product_key: str) -> str:
    """입력 기반 MD5 캐시 키 생성 (개인정보 제외, 분석 의도 기반)"""
    import hashlib
    _raw = json.dumps({"q": query[:500], "pk": product_key}, sort_keys=True, ensure_ascii=False)
    return "analysis_cache/" + hashlib.md5(_raw.encode("utf-8")).hexdigest() + ".json"

def _gcs_cache_get(cache_key: str, question_hint: str = "") -> str | None:
    """GCS에서 캐시 조회 — 없으면 None 반환.

    [가이딩 프로토콜 제38조 §4 Cache-First]
    조회 순서:
      1. 세션 로컬 캐시 (_art38_local_cache) — 네트워크 0회
      2. GCS consulting_cache/{md5}.json — 야간 워커 생성 정교 답변
      3. GCS analysis_cache/{key}.json — 기존 실시간 캐시
    """
    # 1) 세션 로컬 캐시 (네트워크 0회)
    if question_hint:
        _local_hit = st.session_state.get("_art38_local_cache", {})
        _c_key = f"consulting_cache/{__import__('hashlib').md5(question_hint.strip().encode()).hexdigest()}.json"
        if _c_key in _local_hit:
            _d = _local_hit[_c_key]
            return _d.get("answer") if isinstance(_d, dict) else str(_d)
    bucket_name = _get_gcs_cache_bucket()
    if not bucket_name:
        return None
    try:
        gcs = _get_gcs_client()
        if not gcs:
            return None
        # 2) consulting_cache 우선 조회 (야간 워커 정교 답변)
        if question_hint:
            _ck = f"consulting_cache/{__import__('hashlib').md5(question_hint.strip().encode()).hexdigest()}.json"
            _cb = gcs.bucket(bucket_name).blob(_ck)
            if _cb.exists():
                import time as _t40gc
                _t0_gc = _t40gc.monotonic()
                _raw = json.loads(_cb.download_as_text(encoding="utf-8"))
                _s40_record_blocking("_gcs_cache_get/consulting",
                                     (_t40gc.monotonic() - _t0_gc) * 1000)
                if "_art38_local_cache" not in st.session_state:
                    st.session_state["_art38_local_cache"] = {}
                st.session_state["_art38_local_cache"][_ck] = _raw
                return _raw.get("answer") if isinstance(_raw, dict) else str(_raw)
        # 3) analysis_cache 기존 조회
        bucket = gcs.bucket(bucket_name)
        blob = bucket.blob(cache_key)
        if blob.exists():
            import time as _t40ga
            _t0_ga = _t40ga.monotonic()
            _result_text = blob.download_as_text(encoding="utf-8")
            _s40_record_blocking("_gcs_cache_get/analysis",
                                 (_t40ga.monotonic() - _t0_ga) * 1000)
            return _result_text
    except Exception:
        pass
    return None

def _gcs_cache_put(cache_key: str, answer: str) -> None:
    """GCS에 분석 결과 캐시 저장 (비동기 처리로 응답 지연 방지)"""
    bucket_name = _get_gcs_cache_bucket()
    if not bucket_name:
        return
    try:
        import threading
        def _upload():
            try:
                gcs = _get_gcs_client()
                if not gcs:
                    return
                payload = json.dumps({"answer": answer, "cached_at": str(date.today())}, ensure_ascii=False)
                gcs.bucket(bucket_name).blob(cache_key).upload_from_string(
                    payload, content_type="application/json"
                )
            except Exception:
                pass
        threading.Thread(target=_upload, daemon=True).start()
    except Exception:
        pass

def _gcs_cache_get_latest_user(user_name: str) -> str | None:
    """Self-Healing: 사용자의 최근 캐시 파일 1개 반환 (Safe Mode 폴백용)"""
    bucket_name = _get_gcs_cache_bucket()
    if not bucket_name:
        return None
    try:
        gcs = _get_gcs_client()
        if not gcs:
            return None
        blobs = list(gcs.bucket(bucket_name).list_blobs(prefix="analysis_cache/", max_results=20))
        if blobs:
            blobs.sort(key=lambda b: b.updated, reverse=True)
            return blobs[0].download_as_text(encoding="utf-8")
    except Exception:
        pass
    return None

# ── Safe Mode 전역 상태 (에러율 기반 자동 전환) ────────────────────────────
_SAFE_MODE_ERRORS = 0      # 현재 세션 에러 카운트
_SAFE_MODE_THRESHOLD = 5   # 5회 이상 에러 시 Safe Mode 진입
_SAFE_MODE_ACTIVE = False

def _safe_mode_record_error():
    global _SAFE_MODE_ERRORS, _SAFE_MODE_ACTIVE
    _SAFE_MODE_ERRORS += 1
    if _SAFE_MODE_ERRORS >= _SAFE_MODE_THRESHOLD:
        _SAFE_MODE_ACTIVE = True

def _safe_mode_reset():
    global _SAFE_MODE_ERRORS, _SAFE_MODE_ACTIVE
    _SAFE_MODE_ERRORS = 0
    _SAFE_MODE_ACTIVE = False

@st.cache_resource
def _get_sb_client_cached(url: str, key: str):
    """Supabase 클라이언트 생성 및 캐시 — url/key가 있을 때만 호출"""
    try:
        _creator = _lazy_sb_create_client()
        if _creator is None:
            return None
        return _creator(url, key)
    except Exception:
        return None

def _get_sb_client():
    """Supabase 클라이언트 반환 — 연결 실패 시 None 캐시 방지
    우선순위 1: HF 환경변수 SUPABASE_URL / SUPABASE_SERVICE_ROLE_KEY
    우선순위 2: secrets.toml [supabase] 섹션
    """
    if not _SB_PKG_OK:
        return None
    try:
        url = os.environ.get("SUPABASE_URL", "").strip()
        key = os.environ.get("SUPABASE_SERVICE_ROLE_KEY", "").strip()
        if not url or not key:
            try:
                _sb_sec = st.secrets.get("supabase", {})
                url = url or _sb_sec.get("url", "").strip()
                key = key or _sb_sec.get("service_role_key", "").strip()
            except Exception:
                pass
        if not url or not key:
            try:
                url = url or st.secrets.get("SUPABASE_URL", "").strip()
                key = key or st.secrets.get("SUPABASE_SERVICE_ROLE_KEY", "").strip()
            except Exception:
                pass
        if not url or not key:
            return None
        # url+key가 있을 때만 캐시 — None이 캐시되는 것을 방지
        return _get_sb_client_cached(url, key)
    except Exception:
        return None

