_GP101_DEFAULT_PERSONA = "breadwinner_3040"


def get_gp101_persona(
    birth_year: int = 0,
    gender: str = "",
    marital: str = "",
    health_flags: list[str] | None = None,
) -> str:
    """
    [GP101 §2] 고객 프로필 → 페르소나 키 반환.

    Parameters
    ----------
    birth_year   : 출생연도 (0이면 미지정)
    gender       : 'M' / 'F' / ''
    marital      : '미혼' / '기혼' / '이혼' / ''
    health_flags : ['cancer', 'stroke', 'dementia', 'disability',
                    'family_history'] 중 해당 항목

    Returns
    -------
    str — _GP101_PERSONA_HOOKS 의 키
    """
    flags = [f.lower() for f in (health_flags or [])]
    age = (2026 - birth_year) if birth_year > 1900 else 0

    if "disability" in flags:
        return "disability_work"
    if "family_history" in flags or "dementia" in flags:
        return "family_history"
    if "cancer" in flags or "stroke" in flags:
        return "critical_illness"
    if age >= 60:
        return "senior_60plus"
    if age >= 50:
        return "menopause_50"
    if age >= 30 and marital in ("기혼", ""):
        return "breadwinner_3040"
    if age >= 20:
        return "single_2030"
    return _GP101_DEFAULT_PERSONA


def generate_gp101_hook(
    persona_key: str,
    gap_keywords: list[str] | None = None,
    insured_name: str = "",
    variant: str = "a",
) -> str:
    """
    [GP101 §3] 페르소나별 1인칭 후킹 문구 생성.

    variant='a' → hook_a (공백/위협 프레임)
    variant='b' → hook_b (해결/희귀성 프레임)
    """
    persona = _GP101_PERSONA_HOOKS.get(
        persona_key, _GP101_PERSONA_HOOKS[_GP101_DEFAULT_PERSONA]
    )
    masked = mask_name_gp92(insured_name) if insured_name else ""
    prefix = f"[{masked}님] " if masked else ""
    sentence = persona["hook_b"] if variant == "b" else persona["hook_a"]
    return prefix + sentence


def render_gp101_hook_card(
    persona_key: str,
    insured_name: str = "",
    gap_keywords: list[str] | None = None,
) -> None:
    """
    [GP101 §7] 심리 타격 카드 렌더링.
    GP92 Step 1 상단에 삽입하여 페르소나별 맞춤 후킹 + 공감 문구를 표시한다.
    """
    import streamlit as _st_inner
    persona = _GP101_PERSONA_HOOKS.get(
        persona_key, _GP101_PERSONA_HOOKS[_GP101_DEFAULT_PERSONA]
    )
    masked = mask_name_gp92(insured_name) if insured_name else ""
    name_tag = f"🧠 {masked}님의 심리 안보 진단" if masked else "🧠 심리 안보 진단"
    hook_a = generate_gp101_hook(persona_key, gap_keywords, insured_name, "a")
    hook_b = generate_gp101_hook(persona_key, gap_keywords, insured_name, "b")
    bg = persona["bg"]
    border = persona["border"]
    color = persona["color"]
    label = persona["label"]
    _st_inner.markdown(f"""
<div style="background:{bg};border-left:5px solid {border};
  border-radius:0 14px 14px 0;padding:18px 22px;margin-bottom:16px;">
  <div style="font-size:0.68rem;font-weight:900;color:{border};
    letter-spacing:0.12em;margin-bottom:4px;">{name_tag}</div>
  <div style="font-size:0.72rem;font-weight:700;color:{color};
    opacity:0.75;margin-bottom:10px;">페르소나: {label}</div>
  <div style="font-size:0.94rem;font-weight:800;color:{color};
    line-height:1.9;margin-bottom:12px;">"{hook_a}"</div>
  <div style="font-size:0.81rem;color:{color};line-height:1.75;
    border-top:1px solid {border}33;padding-top:10px;opacity:0.9;">"{hook_b}"</div>
</div>""", unsafe_allow_html=True)


def generate_gp92_hook(
    gap_keywords: list[str],
    insured_name: str = "",
    variant: str = "a",
) -> str:
    """
    [GP92 §1] 보장 공백 키워드 → 피보험자 1인칭 후킹 문장 생성.

    Parameters
    ----------
    gap_keywords : 보장 공백이 발생한 담보명·질환명 리스트
    insured_name : 피보험자 원본 이름 (마스킹은 내부에서 처리)
    variant      : 'a' 또는 'b' — 두 가지 버전 중 선택

    Returns
    -------
    str — 마스킹된 이름이 앞에 붙은 1인칭 후킹 문장
    """
    masked = mask_name_gp92(insured_name) if insured_name else ""
    prefix = f"[{masked}님의 이야기] " if masked else ""

    joined = " ".join(gap_keywords).lower()
    for rule in _GP92_HOOK_RULES:
        if any(k.lower() in joined for k in rule["keys"]):
            sentence = rule["hook_b"] if variant == "b" else rule["hook_a"]
            return prefix + sentence

    return prefix + _GP92_DEFAULT_HOOK


# ==========================================================================
# [GP102] 소득 역산 기반 안보 공백 타격 엔진
# 제102조: 건강보험료 → 월소득 역산 → 2년치 휴업손해 → Max(표준, 역산) Gap 산출
# ==========================================================================

_GP102_STANDARD_BASELINES: dict = {
    "cancer":     100_000_000,   # 암 표준 1억
    "brain":       80_000_000,   # 뇌졸중 표준 8천만
    "heart":       80_000_000,   # 심장 표준 8천만
    "disability": 300_000_000,   # 장해 표준 3억
    "death":      200_000_000,   # 사망 표준 2억
    "nursing":     60_000_000,   # 간병 표준 6천만
    "default":    100_000_000,   # 기본 1억
}

_GP102_TREAT_MONTHS: int = 24   # 치료·휴업 기간 24개월
_GP102_TREAT_FIXED:  int = 100_000_000  # 표준 치료비 1억


def _gp102_calc(
    nhis_premium_monthly: float,
    coverage_type: str = "default",
    current_coverage: float = 0.0,
) -> dict:
    """
    [GP102 §2] 건강보험료 기반 소득 역산 → 필요 보장액 산출.

    Parameters
    ----------
    nhis_premium_monthly : 월 건강보험료 (원)
    coverage_type        : 'cancer'/'brain'/'heart'/'disability'/'death'/'nursing'/'default'
    current_coverage     : 현재 보장액 (원, 0 이면 미가입)

    Returns
    -------
    dict {
        monthly_income   : 월 추정 소득,
        monthly_loss     : 월 소득 손실,
        total_loss_24m   : 24개월 휴업손해,
        need_reverse     : 역산 필요 보장액 (손해 + 치료비),
        need_standard    : 표준 기준 보장액,
        need_final       : Max(표준, 역산),
        gap              : need_final - current_coverage,
        gap_pct          : gap / need_final * 100,
        rate_used        : 적용 요율,
    }
    """
    rate = _CURRENT_NHIS_RATE or _ART32_NHIS_RATE_2024
    monthly_income  = nhis_premium_monthly / rate if rate > 0 else 0.0
    monthly_loss    = monthly_income
    total_loss_24m  = monthly_loss * _GP102_TREAT_MONTHS
    need_reverse    = total_loss_24m + _GP102_TREAT_FIXED
    need_standard   = float(_GP102_STANDARD_BASELINES.get(coverage_type, _GP102_STANDARD_BASELINES["default"]))
    need_final      = max(need_standard, need_reverse)
    gap             = max(0.0, need_final - current_coverage)
    gap_pct         = (gap / need_final * 100) if need_final > 0 else 0.0
    return {
        "monthly_income":  monthly_income,
        "monthly_loss":    monthly_loss,
        "total_loss_24m":  total_loss_24m,
        "need_reverse":    need_reverse,
        "need_standard":   need_standard,
        "need_final":      need_final,
        "gap":             gap,
        "gap_pct":         gap_pct,
        "rate_used":       rate,
    }


