# [D2] AI 카카오톡 영업 멘트 자동 생성 — generateKakaoMessage()
# 공식: 30년 베테랑 시스템 프롬프트 + 감시 금지 가이딩 프로토콜 적용
# --------------------------------------------------------------------------
def _generate_kakao_draft(customer_id: str, interest_keyword: str) -> str:
    """고객 entity_id + 관심 키워드 → Gemini로 카톡 초안 생성.

    가이딩 프로토콜 수칙:
      1. "앱에서 검색하신 걸 봤다"는 감시성 멘트 절대 금지
      2. 날씨·계절 등 가벼운 안부로 시작
      3. 해당 질환 관련 건강/보험 트렌드 자연스럽게 언급
      4. 3~4문장 이내, 이모티콘 1~2개
    """
    try:
        _cl = get_client()
        if _cl is None:
            return "⚠️ GEMINI_API_KEY가 설정되지 않아 초안을 생성할 수 없습니다."
        _cfg = _lazy_genai_types().GenerateContentConfig(
            temperature=0.7,
            top_p=0.9,
            system_instruction=(
                "[GP-CONVERSE §5 카카오톡 전용 화법] "
                "너는 30년 경력의 베테랑 보험 설계사다. "
                "고객에게 직접 1:1로 말하는 형태로 카카오톡 메시지를 작성한다. "
                "3인칭('설계사는...', '보험사는...')을 절대 쓰지 않는다. "
                "항상 '고객님, 제가...' 또는 '제가 확인해 보니...' 형태의 1인칭 화법을 사용한다. "
                "전문성(수치·근거 1개)과 친밀감(이모티콘 1~2개)을 동시에 담아야 한다. "
                "마지막 문장은 고객이 바로 답장하고 싶게 만드는 질문 또는 CTA로 마무리한다. "
                "절대 고객이 감시받는다는 느낌을 주지 않는다."
            ),
        )
        _prompt = (
            f"[GP-CONVERSE §5] 카카오톡 1:1 대화체 메시지 초안 작성\n"
            f"고객: {customer_id}님\n"
            f"관심 분야: {interest_keyword}\n\n"
            "[필수 구조 — 3~5문장]\n"
            "1. 가벼운 안부로 시작 (날씨·계절·건강 — 감시 느낌 절대 금지)\n"
            f"2. '{interest_keyword}' 관련 최신 정보 1문장 (법령·보도자료 근거 포함 권장)\n"
            "3. '제가 꼼꼼히 살펴봤더니...' 또는 '솔직히 말씀드리면...' 형태로 핵심 조언 1문장\n"
            "4. 이모티콘 1~2개 자연스럽게 포함\n"
            "5. '편하게 연락 주세요' 또는 '한 번 여쭤봐도 될까요?' 형태의 따뜻한 마무리\n"
            "출력: 메시지 본문만 (인사말 포함, 서명 제외)"
        )
        _resp = _cl.models.generate_content(
            model=GEMINI_MODEL,
            contents=_prompt,
            config=_cfg,
        )
        return (_resp.text or "").strip()
    except Exception as _e:
        return f"메시지 생성 중 오류가 발생했습니다. 직접 입력해 주세요.\n(오류: {_e})"

