def _voice_navigate(text: str):
    """음성/텍스트 입력에서 Intent 감지 → 이동할 current_tab 반환.
    반환값:
      - str  : 단일 매칭 — 해당 tab_key
      - list : 중복 매칭 — [{"tab_key":..,"name":..,"code":..}, ...]
      - None : 매칭 없음
    우선순위:
      0순위: 4자리 코드 직접 매칭 (SECTOR_CODES + SUB_CODES 통합)
      1차:   SUB_CODES 키워드 원문 매칭 (더 구체적이므로 SECTOR보다 우선)
      2차:   SECTOR_CODES 키워드 원문 매칭
      3차:   공백 제거 후 SUB+SECTOR 통합 재매칭
    """
    import re as _re
    if not text or not text.strip():
        return None
    t = text.strip()

    # 0순위 — 4자리 코드 직접 추출 (SECTOR + SUB 통합)
    _id_match = _re.search(r'\b(\d{4})\b', t)
    if _id_match:
        _code = _id_match.group(1)
        if _code in _ALL_CODES:
            _entry = _ALL_CODES[_code]
            return _entry["tab_key"]

    t_lower = t.lower()
    t_nospace = t_lower.replace(" ", "").replace(".", "").replace(",", "")

    # 1차 — SUB_CODES 원문 키워드 매칭 (구체적 용어 우선)
    _sub_hits: list[dict] = []
    for _code, _entry in SUB_CODES.items():
        if any(kw.lower() in t_lower for kw in _entry["keywords"]):
            _sub_hits.append({"tab_key": _entry["tab_key"], "name": _entry["name"], "code": _code})
    if len(_sub_hits) == 1:
        return _sub_hits[0]["tab_key"]
    if len(_sub_hits) > 1:
        # 중복 탭이면 첫 번째로 단일 반환, 다른 탭이면 선택지 반환
        _tabs = list({h["tab_key"] for h in _sub_hits})
        if len(_tabs) == 1:
            return _tabs[0]
        return _sub_hits  # 다중 선택 UI 표시용

    # 2차 — SECTOR_CODES 원문 키워드 매칭
    for tab_key, keywords in _NAV_INTENT_MAP:
        if any(kw.lower() in t_lower for kw in keywords):
            return tab_key

    # 3차 — 공백 제거 후 SUB+SECTOR 통합 재매칭
    _sub_hits2: list[dict] = []
    for _code, _entry in SUB_CODES.items():
        if any(kw.lower().replace(" ", "") in t_nospace for kw in _entry["keywords"]):
            _sub_hits2.append({"tab_key": _entry["tab_key"], "name": _entry["name"], "code": _code})
    if len(_sub_hits2) == 1:
        return _sub_hits2[0]["tab_key"]
    if len(_sub_hits2) > 1:
        _tabs2 = list({h["tab_key"] for h in _sub_hits2})
        if len(_tabs2) == 1:
            return _tabs2[0]
        return _sub_hits2

    for tab_key, keywords in _NAV_INTENT_MAP:
        if any(kw.lower().replace(" ", "") in t_nospace for kw in keywords):
            return tab_key

    return None


def log_error(msg: str, sector_id: str = "", tab_key: str = "", exc: Exception = None) -> None:
    """런타임 오류 기록 — /tmp/gk_error_log.json (최근 300건 순환 저장)
    sector_id: SECTOR_CODES 4자리 ID (어느 섹터에서 오류 발생했는지 즉시 파악)
    tab_key:   current_tab 키 (섹터 ID를 모를 때 tab_key로 역조회 가능)
    exc:       Exception 객체 (traceback 포함 저장)
    """
    import json as _j, traceback as _tb, datetime as _dt
    _log_path = pathlib.Path(tempfile.gettempdir()) / "gk_error_log.json"
    try:
        _entries = _j.loads(_log_path.read_text("utf-8")) if _log_path.exists() else []
    except Exception:
        _entries = []
    # sector_id가 없으면 tab_key로 역조회
    _sid = sector_id
    if not _sid and tab_key:
        for _k, _v in SECTOR_CODES.items():
            if _v["tab_key"] == tab_key:
                _sid = _k
                break
    _entry = {
        "ts":        _dt.datetime.now().strftime("%Y-%m-%d %H:%M:%S"),
        "sector_id": _sid,
        "sector_nm": SECTOR_CODES.get(_sid, {}).get("name", "") if _sid else "",
        "tab_key":   tab_key or "",
        "msg":       str(msg),
        "tb":        _tb.format_exc() if exc else "",
    }
    _entries.append(_entry)
    if len(_entries) > 300:
        _entries = _entries[-300:]
    try:
        _log_path.write_text(_j.dumps(_entries, ensure_ascii=False, indent=2), "utf-8")
    except Exception:
        pass


def stt_correct(text: str) -> str:
    """STT 결과 후처리 — 보험 전문용어 오인식 자동 교정 (매핑 테이블 기반)"""
    for correct, wrong_list in _STT_CORRECT_MAP.items():
        for wrong in wrong_list:
            text = text.replace(wrong, correct)
    return text

_STT_LLM_SYSTEM_PROMPT = """너는 대한민국 보험 전문 상담사 및 언어학 전문가이다.
입력되는 텍스트는 STT(음성인식) 엔진을 통해 변환된 것으로,
경상도/전라도/충청도 등 강한 사투리와 음성 인식 오류(오타)가 포함되어 있다.
너의 임무는 이를 보험 상담 맥락에 맞게 표준어로 교정하는 것이다.

[핵심 지시 사항]
1. 의미 보존: 사용자의 의도(의문·불만·요청)를 100% 유지할 것
2. 보험 용어 교정: "실비아"→"실손의료보험", "치매 보험"→"치매보험" 등 문맥 기반 교정
3. 사투리 매핑: 지역별 종결어미("-노","-당께","-해유","-가꼬","-인디","-능가")를 표준어로 변환
4. 출력 형식: 교정된 문장만 출력할 것. 설명·부연·추가 내용 생성 절대 금지
5. 원문에 없는 내용을 절대 추가하지 말 것 (Hallucination 방지)
6. 이미 표준어인 경우 그대로 반환할 것

[Few-Shot 예시]
Input: "이거 보험료가 억수로 비싸가꼬 좀 깎아주이소"
Output: "이 보험료가 매우 비싸서 조금 할인해 주세요"

Input: "내 아까 가입했는디 왜 문자가 안 오능가"
Output: "제가 조금 전에 가입했는데 왜 문자가 오지 않습니까"

Input: "실비아 있으면 병원비 다 나오는 거 아닝교"
Output: "실손의료보험이 있으면 병원비가 다 나오는 건가요"

Input: "치매 걸리면 보험금 얼마나 나와유"
Output: "치매에 걸리면 보험금이 얼마나 나오나요"

Input: "납입 면재 특약이 뭔지 설명해 줘봐"
Output: "납입면제 특약이 무엇인지 설명해 주세요"

Input: "이 상품 갱신형인가요 비갱신형인가요"
Output: "이 상품은 갱신형인가요, 비갱신형인가요"
"""

def stt_llm_correct(text: str, client=None, strictness: float = 0.7) -> str:
    """STT 결과 LLM 기반 사투리·오인식 교정 (Context-Aware Normalization)
    - 매핑 테이블 교정(stt_correct) 이후 2차 후처리로 사용
    - temperature=0.1: 일관성 확보, Hallucination 방지
    - strictness (0.0~1.0): 교정 강도 파라미터
        0.3 이하 — 보험 용어 오인식만 교정, 사투리 어투 유지
        0.7 (기본) — 보험 용어 + 주요 사투리 종결어미 교정
        1.0 — 전면 표준어 교정 (고강도, Hallucination 위험↑)
    - client가 None이거나 호출 실패 시 원문 반환 (Graceful Degradation)
    """
    if not text or not text.strip():
        return text
    strictness = max(0.0, min(1.0, strictness))  # 0~1 클램프
    # 짧은 입력은 LLM 호출 불필요
    if len(text) <= 20:
        return text
    # 사투리 키워드 감지 — 없으면 LLM 호출 생략 (비용/지연 절약)
    _dialect_markers = [
        "가꼬", "이소", "이소요", "인디", "능가", "당께", "해유", "랑께",
        "하이소", "드이소", "주이소", "가이소", "-노", "아이가", "아임마",
        "억수로", "겁나", "와", "와요", "예", "예요", "아잉교", "닝교",
        "뭐라카노", "어찌", "어케", "워째", "그랬는디", "했는디",
    ]
    has_dialect = any(m in text for m in _dialect_markers)
    # STT 오인식 패턴 감지 (공백 삽입 오류 등)
    _stt_noise = ["실비아", "납입 면재", "치매 보험", "실손 의료비", "뇌혈관 질환"]
    has_noise = any(n in text for n in _stt_noise)

    if not has_dialect and not has_noise:
        return text  # 교정 불필요

    if client is None:
        try:
            client, _ = get_master_model()
        except Exception:
            return text

    # strictness에 따라 교정 지시 강도 동적 조정
    if strictness <= 0.3:
        _strict_directive = (
            "\n[교정 강도: 최소] 보험 전문용어 오인식(예: 실비아→실손의료보험)만 교정하고, "
            "사투리 어투·종결어미는 그대로 유지할 것."
        )
        _max_len_ratio = 1.3   # 교정 후 길이가 원문의 1.3배 초과 시 원문 반환
    elif strictness <= 0.7:
        _strict_directive = (
            "\n[교정 강도: 표준] 보험 전문용어 + 주요 사투리 종결어미만 교정. "
            "문장 전체를 재작성하지 말고 최소한의 수정만 할 것."
        )
        _max_len_ratio = 1.6
    else:
        _strict_directive = (
            "\n[교정 강도: 고강도] 전체 문장을 자연스러운 표준어로 교정. "
            "단, 원문의 의미와 질문 의도는 100% 보존할 것."
        )
        _max_len_ratio = 2.0

    try:
        # [수칙5 수정] 교정 지시문(system)과 사용자 음성텍스트(user)를 분리
        # _STT_LLM_SYSTEM_PROMPT + _strict_directive → system_instruction으로 주입
        # 실제 교정 입력만 user role로 전달 (기존 user role 오남용 제거)
        _stt_call_config = _lazy_genai_types().GenerateContentConfig(
            temperature=0.1,
            top_p=0.2,
            max_output_tokens=512,
            system_instruction=_STT_LLM_SYSTEM_PROMPT + _strict_directive,
        )
        resp = client.models.generate_content(
            model="gemini-2.0-flash",
            contents=[
                {"role": "user", "parts": [{"text": f"Input: \"{text}\"\nOutput:"}]}
            ],
            config=_stt_call_config,
        )
        corrected = resp.text.strip().strip('"').strip("'")
        # Hallucination 방지: 교정 결과가 원문 대비 _max_len_ratio 초과 시 원문 반환
        if corrected and len(corrected) <= len(text) * _max_len_ratio:
            return corrected
        return text
    except Exception:
        return text

def _tts_normalize(text: str) -> str:
    """TTS 출력 전처리 — 마크다운 제거, 숫자/단위 정규화, 자연어 pause 삽입"""
    import re
    t = sanitize_unicode(text)
    # 마크다운 제거
    t = re.sub(r'#{1,6}\s*', '', t)          # 헤딩
    t = re.sub(r'\*{1,3}([^*]+)\*{1,3}', r'\1', t)  # bold/italic
    t = re.sub(r'`{1,3}[^`]*`{1,3}', '', t)  # 코드블록
    t = re.sub(r'\[([^\]]+)\]\([^)]+\)', r'\1', t)  # 링크
    t = re.sub(r'^[-*>|]+\s*', '', t, flags=re.MULTILINE)  # 목록/인용/표
    # 숫자+단위 자연어 변환 (TTS 오독 방지)
    t = re.sub(r'(\d+)%', r'\1 퍼센트', t)
    t = re.sub(r'(\d+)원', r'\1 원', t)
    t = re.sub(r'(\d+)만원', r'\1 만원', t)
    t = re.sub(r'(\d+)억원', r'\1 억원', t)
    t = re.sub(r'(\d+)ms', r'\1 밀리초', t)
    # 문장 끝 pause — 마침표·물음표·느낌표 뒤 공백 정리
    t = re.sub(r'([.?!。？！])\s*', r'\1 ', t)
    # 줄바꿈 → 공백
    t = t.replace('\n', ' ')
    # 특수문자 제거 (JS 문자열 이스케이프 방지)
    t = t.replace('"', '').replace("'", '').replace('`', '').replace('\\', '')
    # 연속 공백 정리
    t = re.sub(r'\s{2,}', ' ', t).strip()
    return t

def _detect_tone(text: str) -> str:
    """상담 텍스트에서 Prosody 톤 자동 감지 — TTS_TONE_PRESETS 키 반환
    우선순위: empathy > calm > clear > bright > default
    """
    t = text.lower()
    # 공감 톤: 사망·입원·진단·암·수술 등 민감 상황
    _empathy_kw = ["사망", "돌아가", "입원", "수술", "암", "진단", "사고", "응급", "위독", "상실", "슬프"]
    if any(k in t for k in _empathy_kw):
        return "empathy"
    # 차분 톤: 보험금 청구·불만·해지·민원
    _calm_kw = ["보험금 청구", "청구", "불만", "항의", "해지", "환급", "민원", "지연", "거절", "왜 안"]
    if any(k in t for k in _calm_kw):
        return "calm"
    # 또렷 톤: 약관·법률·설명의무 등 정확성 중시
    _clear_kw = ["약관", "법", "설명의무", "청약", "철회", "면책", "면제", "특약 내용", "조항"]
    if any(k in t for k in _clear_kw):
        return "clear"
    # 밝은 톤: 상품 안내·신규 가입·추천
    _bright_kw = ["상품 안내", "추천", "가입", "혜택", "할인", "프로모션", "신규", "소개", "이벤트"]
    if any(k in t for k in _bright_kw):
        return "bright"
    return "default"

def s_voice(text, lang=None, elderly=False, tone: str = "auto"):
    """TTS - 전역 TTS_* 상수 강제 적용 + Prosody Control + 자연어 전처리(_tts_normalize)
    elderly=True 시 TTS_RATE_ELDERLY(0.75) 적용 — 고령 고객 응대용
    tone: "auto"(컨텍스트 자동 감지) | "default"|"calm"|"bright"|"empathy"|"clear"
    """
    lang = lang or TTS_LANG
    if elderly:
        rate  = TTS_RATE_ELDERLY
        pitch = TTS_PITCH
    else:
        # Prosody Control: tone 파라미터 기반 rate/pitch 결정
        _tone = _detect_tone(text) if tone == "auto" else tone
        _preset = TTS_TONE_PRESETS.get(_tone, TTS_TONE_PRESETS["default"])
        rate  = _preset[0]
        pitch = _preset[1]
    vp    = '||'.join(f'v.name.includes("{n}")' for n in TTS_VOICE_PRIORITY)
    clean = _tts_normalize(text)
    return (
        '<script>'
        'window.speechSynthesis.cancel();'
        f'var msg=new SpeechSynthesisUtterance("{clean}");'
        f'msg.lang="{lang}";'
        f'msg.rate={rate};'
        f'msg.pitch={pitch};'
        f'msg.volume={TTS_VOLUME};'
        'var voices=window.speechSynthesis.getVoices();'
        f'var femaleVoice=voices.find(function(v){{return v.lang==="{lang}"&&({vp});}});'
        'if(femaleVoice) msg.voice=femaleVoice;'
        'window.speechSynthesis.speak(msg);'
        '</script>'
    )

def s_voice_answer(text):
    """AI 답변 음성 읽기 - 첫 250자만 읽음 (마크다운/특수문자 전처리 포함)
    Prosody Control: 답변 텍스트 기반 tone 자동 감지 적용"""
    short = _tts_normalize(text)[:250]
    return s_voice(short, tone="auto")

def load_stt_engine():
    """STT 엔진 초기화 - 실시간 받아쓰기(continuous) 방식 (1회만 호출)"""
    stt_js = """
<script>
if(!window._sttInit){
  window._sttInit=true;
  window._sttActive=false;
  window._sttRec=null;
  window._sttFinal='';

  window.startRecognition=function(lang, targetId, interimId){
    var SR=window.SpeechRecognition||window.webkitSpeechRecognition;
    if(!SR){alert('Chrome/Edge 브라우저를 사용해주세요.');return;}
    if(window._sttActive){
      if(window._sttRec) window._sttRec.stop();
      window._sttActive=false; return;
    }
    var r=new SR();
    r.lang=lang||'ko-KR';          // STT_LANG 강제
    r.interimResults=true;          // STT_INTERIM
    r.continuous=true;              // STT_CONTINUOUS
    r.maxAlternatives=1;
    window._sttFinal='';

    r.onresult=function(e){
      var interim=''; var final_new='';
      for(var i=e.resultIndex;i<e.results.length;i++){
        if(e.results[i].isFinal){ final_new+=e.results[i][0].transcript; }
        else { interim+=e.results[i][0].transcript; }
      }
      if(final_new){
        window._sttFinal+=final_new;
        var ta=targetId?document.getElementById(targetId):null;
        if(!ta){ var all=document.querySelectorAll('textarea'); ta=all[all.length-1]; }
        if(ta){
          var s=Object.getOwnPropertyDescriptor(window.HTMLTextAreaElement.prototype,'value').set;
          s.call(ta,window._sttFinal);
          ta.dispatchEvent(new Event('input',{bubbles:true}));
        }
      }
      if(interimId){
        var el=document.getElementById(interimId);
        if(el) el.textContent=interim?'🎤 '+interim:'';
      }
    };
    r.onerror=function(e){
      if(e.error==='no-speech'||e.error==='aborted') return;
    };
    r.onend=function(){
      if(window._sttActive){ try{r.start();}catch(ex){} }
    };
    window._sttRec=r;
    window._sttActive=true;
    r.start();
  };

  window.stopRecognition=function(){
    if(window._sttRec) window._sttRec.stop();
    window._sttActive=false;
  };
}
</script>"""
    components.html(stt_js, height=0)

def output_manager(masked_name, result_text):
    """분석 결과 세션 저장 및 출력"""
    st.session_state.analysis_result = result_text
    st.divider()
    st.subheader(f"{masked_name}님 분석 결과")
    st.markdown(result_text)
    st.info("[주의] 본 분석 결과의 최종 책임은 사용자(상담원)에게 귀속됩니다.")


# ── [가이딩 프로토콜 제88조] 통합 상담 자산 관리 허브 ──────────────────────
def _gp88_hub() -> dict:
    """GP88 통합 대시보드 허브 — §1 검색·§2 OCR·§3 10대 명품 문구·§4 카카오 허브
    반환값: {'selected_script': str, 'ocr_result': dict, 'prefill': dict}
    """
    import datetime as _dt, re as _re, json as _json

    _HUB_KEY    = "_gp88_hub_open"
    _SCRIPT_KEY = "_gp88_selected_script"
    _OCR_KEY    = "_gp88_ocr_result"
    _HIST_KEY   = "_gp88_consult_history"

    # ── 세션 초기화 ──────────────────────────────────────────────────────────
    for _k, _dv in [(_HUB_KEY, False), (_SCRIPT_KEY, ""), (_OCR_KEY, {}), (_HIST_KEY, [])]:
        if _k not in st.session_state:
            st.session_state[_k] = _dv

    # ── 상담 이력 자동 적재 (이번 세션 result_* 키 수집) ────────────────────
    _hist: list = st.session_state[_HIST_KEY]
    for _sk, _sv in st.session_state.items():
        if (isinstance(_sk, str) and _sk.startswith("result_")
                and isinstance(_sv, str) and len(_sv) > 30):
            _already = any(h.get("key") == _sk for h in _hist)
            if not _already:
                _m_name = _re.search(r"([가-힣]{2,5})님", _sv)
                _m_amt  = _re.search(r"(\d[\d,\.]+\s*억|[1-9]\d*,?\d{3}만\s*원|\d+억)", _sv)
                _hist.append({
                    "key":   _sk,
                    "name":  _m_name.group(1) if _m_name else st.session_state.get("current_c_name", ""),
                    "amount": _m_amt.group(0) if _m_amt else "",
                    "ts":    _dt.datetime.now().strftime("%Y-%m-%d %H:%M"),
                    "text":  _sv,
                })
    st.session_state[_HIST_KEY] = _hist

    # 허브 토글 버튼
    if st.button("🏛️ GP88 통합 상담 허브 열기/닫기",
                 key="_gp88_toggle_btn", use_container_width=True):
        st.session_state[_HUB_KEY] = not st.session_state[_HUB_KEY]

    if not st.session_state[_HUB_KEY]:
        return {"selected_script": st.session_state.get(_SCRIPT_KEY, ""),
                "ocr_result": st.session_state.get(_OCR_KEY, {}),
                "prefill": {}}

    st.markdown("---")
    st.markdown("## 🏛️ GP88 통합 상담 자산 관리 허브")

    _tab_search, _tab_ocr, _tab_scripts, _tab_kakao = st.tabs([
        "🔍 §1 상담 검색",
        "📄 §2 계약서 스캔",
        "✍️ §3 10대 명품 문구",
        "📲 §4 카카오 허브",
    ])

    _prefill: dict = {}

    # ══════════════════════════════════════════════════════════════════════════
    # §1 상담 이력 검색
    # ══════════════════════════════════════════════════════════════════════════
    with _tab_search:
        st.markdown("#### 🔍 키워드로 과거 상담 즉시 호출")
        _q = st.text_input("이름 · 날짜 · 키워드 입력", placeholder="예: 홍길동 / 상속 / 2026-03",
                           key="_gp88_search_q")
        if _hist:
            _filtered = [h for h in _hist
                         if not _q or _q in h.get("name","") or _q in h.get("ts","")
                         or _q in h.get("text","") or _q in h.get("amount","")]
            if _filtered:
                for _h in reversed(_filtered[-20:]):
                    with st.expander(
                        f"🕐 {_h['ts']} | {_h['name'] or '(미상)'} | {_h['amount'] or '금액 미확인'}",
                        expanded=False
                    ):
                        st.markdown(_h["text"][:600] + ("…" if len(_h["text"]) > 600 else ""))
                        if st.button("이 상담으로 증서 발급", key=f"_gp88_load_{_h['key']}"):
                            _prefill["result_text"] = _h["text"]
                            _prefill["name"]        = _h["name"]
                            _prefill["value"]       = _h["amount"]
                            st.success(f"✅ '{_h['name']}' 상담 내용을 증서 폼에 불러왔습니다.")
            else:
                st.info("🔎 검색 결과가 없습니다.")
        else:
            st.info("📭 이번 세션에 저장된 상담 이력이 없습니다. 상담 분석을 먼저 실행하세요.")

    # ══════════════════════════════════════════════════════════════════════════
    # §2 계약서 OCR 스캔
    # ══════════════════════════════════════════════════════════════════════════
    with _tab_ocr:
        st.markdown("#### 📄 계약서/증권 스캔 → 핵심 담보 자동 추출")
        # ── [GP193 §4] 전역 지식 베이스 업데이트 배지 ─────────────────────
        try:
            from modules.scan_engine import render_gp193_live_badge as _rgb
            _badge_html = _rgb(session_state=st.session_state)
            if _badge_html:
                st.markdown(_badge_html, unsafe_allow_html=True)
        except Exception:
            pass
        st.caption("PDF 또는 이미지(JPG·PNG)를 업로드하면 Gemini Vision AI가 핵심 담보를 읽어냅니다.")
        st.markdown('<div class="gk-scan-wrap">', unsafe_allow_html=True)
        _ocr_file = st.file_uploader(
            "계약서 파일 업로드 (PDF · JPG · PNG)",
            type=["pdf", "jpg", "jpeg", "png"],
            key="_gp88_ocr_upload",
        )
        st.markdown('</div>', unsafe_allow_html=True)

        # ── [GP196 §1] 파일 용량 사전 검사 ────────────────────────────────
        if _ocr_file:
            _ocr_raw_bytes = _ocr_file.read()
            _ocr_file.seek(0)
            _ocr_size_mb = len(_ocr_raw_bytes) / (1024 * 1024)
            if len(_ocr_raw_bytes) > 10 * 1024 * 1024:
                st.warning(
                    f"⚠️ 용량이 너무 큽니다 ({_ocr_size_mb:.1f} MB). "
                    "10 MB 이하로 최적화 후 다시 올려주세요."
                )
                _ocr_file = None
            else:
                st.caption(f"📦 파일 크기: {_ocr_size_mb:.2f} MB — 정상 범위")

        # ── [GP193 §2] 전역 인제스트 후크 ─────────────────────────────────
        if _ocr_file and st.session_state.get("_gp193_done_gp88_ocr_upload") != _ocr_file.name:
            try:
                from modules.scan_engine import global_ingest_hook as _gih
                _gih_p = _gp193_get_hook_params()
                with st.spinner("🌐 지능형 자산화 진행 중..."):
                    _gih_r = _gih(
                        file_bytes=_ocr_raw_bytes,
                        filename=_ocr_file.name,
                        source_tab="gp88_ocr_scan",
                        doc_type="보험약관",
                        **_gih_p,
                    )
                if _gih_r.get("success"):
                    st.success("✅ 전역 지식 베이스 업데이트 완료")
                st.session_state["_gp193_done_gp88_ocr_upload"] = _ocr_file.name
            except Exception:
                pass

        if _ocr_file and st.button("🔍 AI 핵심 담보 추출 시작", key="_gp88_ocr_run",
                                   type="primary", use_container_width=True):
            import io as _io
            _ext = _ocr_file.name.rsplit(".", 1)[-1].lower()

            # ── [GP196 §2] 이미지 리사이징 ────────────────────────────────
            try:
                from modules.scan_engine import resize_image_bytes as _resize_img
                _ocr_raw_bytes = _resize_img(_ocr_raw_bytes, _ocr_file.name)
            except Exception:
                pass

            # ── [GP196 §3+§4] 프로그레스 바 + 배치 처리 ──────────────────
            _ocr_prog = st.progress(0, text="🔍 분석 준비 중...")
            _ocr_status = st.empty()
            _client = get_client()

            if _client is None:
                st.error("GEMINI_API_KEY가 설정되지 않았습니다.")
            else:
                _vision_prompt = (
                    "이 보험 계약서/증권 이미지에서 다음 항목을 추출하여 JSON으로 반환하세요:\n"
                    '{"계약자":"","피보험자":"","보험사":"","상품명":"","납입기간":"","보험기간":"",'
                    '"월보험료":"","사망보험금":"","암진단비":"","뇌진단비":"","심장진단비":"",'
                    '"실손보험료":"","기타담보":[]}\n'
                    "없는 항목은 빈 문자열로, 기타담보는 이름과 금액 쌍의 리스트로 표현하세요."
                )
                _types = _lazy_genai_types()
                _merged_data = {}
                _page_error_count = 0

                if _ext == "pdf":
                    # ── PDF 배치 처리 (Generator, 5페이지씩) ──────────────
                    try:
                        from modules.scan_engine import iter_pdf_pages as _iter_pages
                        _batches = list(_iter_pages(_ocr_raw_bytes, batch_size=5))
                    except Exception:
                        _batches = [([ None], [_ocr_raw_bytes])]

                    _total_batches = max(len(_batches), 1)
                    for _bi, (_page_idxs, _page_imgs) in enumerate(_batches):
                        _pct = int((_bi / _total_batches) * 90) + 5
                        _page_label = (
                            f"p.{_page_idxs[0]+1}~{_page_idxs[-1]+1}"
                            if _page_idxs[0] is not None else "전체"
                        )
                        _ocr_prog.progress(_pct, text=f"📄 {_page_label} 분석 중... ({_bi+1}/{_total_batches})")
                        _ocr_status.markdown(
                            f"<span style='font-size:0.78rem;color:#64748b;'>"
                            f"배치 {_bi+1}/{_total_batches} 처리 중...</span>",
                            unsafe_allow_html=True
                        )
                        try:
                            _batch_img = _page_imgs[0]  # 배치 대표 이미지
                            _resp = _client.models.generate_content(
                                model=GEMINI_MODEL,
                                contents=[
                                    _types.Part.from_bytes(data=_batch_img, mime_type="image/jpeg"),
                                    _vision_prompt,
                                ],
                            )
                            _raw_txt = _resp.text.strip()
                            _jm = _re.search(r"\{[\s\S]+\}", _raw_txt)
                            if _jm:
                                try:
                                    _batch_data = _json.loads(_jm.group(0))
                                    for _k, _v in _batch_data.items():
                                        if _v and not _merged_data.get(_k):
                                            _merged_data[_k] = _v
                                except Exception:
                                    pass
                        except MemoryError:
                            _page_error_count += 1
                            _ocr_status.warning(
                                f"⚠️ {_page_label} 처리 중 메모리 부족 — 해당 배치를 건너뜁니다. "
                                "다음 페이지부터 계속합니다."
                            )
                        except Exception as _batch_err:
                            _page_error_count += 1
                            _ocr_status.warning(
                                f"⚠️ {_page_label} 처리 중 오류 발생 — 건너뜁니다. "
                                f"({str(_batch_err)[:80]})"
                            )
                else:
                    # ── 이미지 단일 처리 ──────────────────────────────────
                    _ocr_prog.progress(30, text="🖼️ 이미지 분석 중...")
                    try:
                        _mime_type = f"image/{_ext.replace('jpg', 'jpeg')}"
                        _resp = _client.models.generate_content(
                            model=GEMINI_MODEL,
                            contents=[
                                _types.Part.from_bytes(data=_ocr_raw_bytes, mime_type=_mime_type),
                                _vision_prompt,
                            ],
                        )
                        _raw_txt = _resp.text.strip()
                        _jm = _re.search(r"\{[\s\S]+\}", _raw_txt)
                        if _jm:
                            try:
                                _merged_data = _json.loads(_jm.group(0))
                            except Exception:
                                _merged_data = {"raw": _raw_txt}
                        else:
                            _merged_data = {"raw": _raw_txt}
                    except MemoryError:
                        _ocr_status.error(
                            "❌ 메모리 부족 — 이미지를 더 작게 줄이거나 해상도를 낮춰주세요."
                        )
                        _merged_data = {}
                    except Exception as _e:
                        _ocr_status.error(f"❌ OCR 오류: {str(_e)[:120]}")
                        _merged_data = {}

                _ocr_prog.progress(100, text="✅ 분석 완료!")
                if _merged_data:
                    st.session_state[_OCR_KEY] = _merged_data
                    _success_msg = "✅ 핵심 담보 추출 완료!"
                    if _page_error_count:
                        _success_msg += f" (오류로 건너뜀: {_page_error_count}배치)"
                    st.success(_success_msg)
                else:
                    st.warning("⚠️ 추출된 데이터가 없습니다. 파일을 확인해 주세요.")

        _ocr_result = st.session_state.get(_OCR_KEY, {})
        if _ocr_result:
            st.markdown("**📋 추출된 계약 정보**")
            if "raw" in _ocr_result:
                st.text_area("원문", value=_ocr_result["raw"], height=200, key="_gp88_ocr_raw")
            else:
                _display_fields = [
                    ("계약자", "계약자"), ("피보험자", "피보험자"), ("보험사", "보험사"),
                    ("상품명", "상품명"), ("납입기간", "납입기간"), ("보험기간", "보험기간"),
                    ("월보험료", "월보험료"), ("사망보험금", "사망보험금"),
                    ("암진단비", "암진단비"), ("뇌진단비", "뇌진단비"), ("심장진단비", "심장진단비"),
                ]
                _cols = st.columns(2)
                for _i, (_lbl, _fk) in enumerate(_display_fields):
                    _v = _ocr_result.get(_fk, "")
                    if _v:
                        _cols[_i % 2].metric(_lbl, _v)
                _extras = _ocr_result.get("기타담보", [])
                if _extras:
                    st.markdown("**기타 담보:**")
                    for _ex in _extras:
                        st.markdown(f"- {_ex}")
                # 증서 폼 자동 채우기 연결
                _pname  = _ocr_result.get("계약자") or _ocr_result.get("피보험자", "")
                _pprice = _ocr_result.get("사망보험금") or _ocr_result.get("월보험료", "")
                _pplan  = _ocr_result.get("상품명", "")
                if st.button("이 계약 정보로 증서 발급 준비", key="_gp88_ocr_to_cert",
                             use_container_width=True):
                    _prefill["name"]  = _pname
                    _prefill["value"] = _pprice
                    _prefill["plan"]  = _pplan
                    st.success(f"✅ '{_pplan}' 계약 정보를 증서 폼에 불러왔습니다.")

    # ══════════════════════════════════════════════════════════════════════════
    # §3 10대 명품 문구
    # ══════════════════════════════════════════════════════════════════════════
    with _tab_scripts:
        st.markdown("#### ✍️ 1인칭 마스터 문구 — 클릭 한 번으로 선택")
        st.caption("선택한 문구는 황금빛 약속 증서 카카오 공유 메시지에 자동 결합됩니다.")

        _MASTER_SCRIPTS = [
            ("👨‍👩‍👧‍👦 가족 생계",
             "내가 없어도 내 아이들이 지금처럼 웃으며 공부할 수 있는 튼튼한 울타리를 내가 직접 세웠습니다."),
            ("🏛️ 상속세 재원",
             "내 평생의 결실이 세금으로 흩어지지 않고 자녀에게 온전히 전달되도록 내가 현금 물길을 열었습니다."),
            ("🏢 CEO 감자플랜",
             "내가 헌신한 이 회사가 가족의 현금 창구가 되어 나를 지켜줄 수 있도록 내가 길을 닦았습니다."),
            ("🌅 노후 독자 생존",
             "누구에게도 짐이 되지 않고, 나 스스로 품위 있는 노후를 보낼 수 있는 마르지 않는 샘물을 내가 팠습니다."),
            ("💰 이자소득 비과세",
             "국가에 낼 세금까지 내 자산으로 확정 짓는, 나만의 세무 방어벽을 내가 구축했습니다."),
            ("🛡️ 납입면제 특약",
             "아픈 순간에도 내 자산은 멈추지 않고 스스로 불어나는 마법 같은 안전장치를 내가 걸었습니다."),
            ("📚 교육비 보장",
             "내 아이의 꿈이 어떤 폭풍우에도 꺾이지 않도록 내가 가장 단단한 뿌리를 심어두었습니다."),
            ("🎖️ 경영인 퇴직금",
             "무사히 완주한 나에게 주는 최고의 보너스를 법인의 이름으로 내가 직접 설계했습니다."),
            ("📈 변액/자산 증식",
             "시대의 흐름에 내 자산을 태워, 가치를 지키고 키워나가는 지혜로운 항해를 내가 시작했습니다."),
            ("🌱 기초 자금 마련",
             "먼 미래의 큰 기회를 놓치지 않도록, 오늘부터 작은 씨앗을 심어 내 숲을 가꾸기 시작했습니다."),
        ]

        _cur_script = st.session_state.get(_SCRIPT_KEY, "")
        if _cur_script:
            st.success(f"✅ 선택된 문구: **{_cur_script[:60]}…**")

        for _idx, (_label, _script) in enumerate(_MASTER_SCRIPTS):
            _col_a, _col_b = st.columns([1, 4])
            with _col_a:
                if st.button(_label, key=f"_gp88_script_{_idx}", use_container_width=True):
                    st.session_state[_SCRIPT_KEY] = _script
                    st.rerun()
            with _col_b:
                st.markdown(
                    f'<div style="background:#FFFDF0;border-left:3px solid #D4AF37;'
                    f'padding:8px 14px;border-radius:0 8px 8px 0;font-size:0.88rem;'
                    f'color:#2c1a00;line-height:1.6;">{_script}</div>',
                    unsafe_allow_html=True,
                )

    # ══════════════════════════════════════════════════════════════════════════
    # §4 카카오톡 통합 발송 블록
    # ══════════════════════════════════════════════════════════════════════════
    with _tab_kakao:
        st.markdown("#### 📲 황금빛 증서 + 명품 문구 → 카카오톡 즉시 전송")
        _sel_script = st.session_state.get(_SCRIPT_KEY, "")
        _ocr_data   = st.session_state.get(_OCR_KEY, {})
        _send_name  = st.text_input("전송 대상 이름",
                                    value=_ocr_data.get("계약자","") or st.session_state.get("current_c_name",""),
                                    key="_gp88_send_name")
        _send_plan  = st.text_input("플랜명",
                                    value=_ocr_data.get("상품명",""),
                                    key="_gp88_send_plan")
        _send_value = st.text_input("실질 이득 수치",
                                    value=_ocr_data.get("사망보험금",""),
                                    key="_gp88_send_value")
        if _sel_script:
            st.markdown(
                f'<div style="background:#f0f9ff;border:1.5px solid #0ea5e9;border-radius:10px;'
                f'padding:10px 16px;font-size:0.88rem;color:#0c4a6e;margin:8px 0;">'
                f'📌 <b>선택된 명품 문구:</b><br>{_sel_script}</div>',
                unsafe_allow_html=True,
            )
        else:
            st.info("💡 §3 탭에서 명품 문구를 먼저 선택하세요.")

        if st.button("📲 카카오톡으로 증서 + 문구 전송", key="_gp88_kakao_send_btn",
                     type="primary", use_container_width=True):
            _combined_value = _send_value or "소중한 재원 확보"
            _combined_plan  = _send_plan  or "황금빛 플랜"
            _combined_name  = _send_name  or "나"
            # GP87 공유 함수 호출
            _gp87_kakao_share(
                name=_combined_name,
                plan=_combined_plan + (f" | {_sel_script[:30]}…" if _sel_script else ""),
                value=_combined_value,
                date=_dt.date.today().strftime("%Y년 %m월 %d일"),
            )

    st.markdown("---")
    return {
        "selected_script": st.session_state.get(_SCRIPT_KEY, ""),
        "ocr_result":      st.session_state.get(_OCR_KEY, {}),
        "prefill":         _prefill,
    }


# ══════════════════════════════════════════════════════════════════════════════
# [GP94] 손해보험 암 상품 실전 화법 엔진
