                            year     = parsed.get("연도", "")
                            prod_nm  = parsed.get("상품명", "미분류")
                            # 파일명: 보험사_상품명_원본명.pdf
                            safe_fn  = _re.sub(r'[\\/:*?"<>|\s]', '_',
                                f"{ins_co}_{prod_nm}_{lf.name}")[:80]
                            if not safe_fn.endswith(".pdf"):
                                safe_fn += ".pdf"
                            gcs_path = _build_gcs_path(doc_type, ins_co, year, safe_fn)

